import { useState, useEffect, useRef } from 'react';
import { Filter, Search, X, ArrowLeft, Trophy, Medal, ChevronDown, Users } from 'lucide-react';
import { Link } from 'react-router-dom';
import { motion, AnimatePresence, useInView } from 'framer-motion';
import toast from 'react-hot-toast';
import { publicAPI } from '../../services/api';
import Dropdown from '../../components/Dropdown';
import { logger } from '../../utils/logger';
import { COLORS, useReducedMotion, GradientText, FadeIn, GlassCard, SaffronButton } from './Home';

// ─── Design tokens ────────────────────────────────────────────────────────────
const EASE_OUT = [0.25, 0.46, 0.45, 0.94];

// ─── Ambient orb ─────────────────────────────────────────────────────────────
const Orb = ({ x, y, size, color, delay, duration, blur = 80 }) => {
  const reduced = useReducedMotion();
  if (reduced) return null;
  return (
    <motion.div
      className="absolute rounded-full pointer-events-none"
      style={{
        left: `${x}%`, top: `${y}%`, width: size, height: size,
        background: `radial-gradient(circle at 35% 35%, ${color}33, ${color}0A, transparent 70%)`,
        filter: `blur(${blur}px)`, transform: 'translate(-50%, -50%)',
      }}
      animate={{ y: [0, -30, 0], scale: [1, 1.1, 1], opacity: [0.3, 0.55, 0.3] }}
      transition={{ duration, delay, repeat: Infinity, ease: 'easeInOut' }}
    />
  );
};

// ─── Rank badge ───────────────────────────────────────────────────────────────
const RankBadge = ({ rank }) => {
  const colors = {
    1: { bg: 'rgba(245,166,35,0.2)', border: 'rgba(245,166,35,0.5)', text: '#F5A623', icon: '🥇' },
    2: { bg: 'rgba(192,192,192,0.15)', border: 'rgba(192,192,192,0.4)', text: '#C0C0C0', icon: '🥈' },
    3: { bg: 'rgba(205,127,50,0.15)', border: 'rgba(205,127,50,0.4)', text: '#CD7F32', icon: '🥉' },
  };
  const c = colors[rank];
  if (c) {
    return (
      <div className="w-8 h-8 rounded-full flex items-center justify-center border text-sm font-black flex-shrink-0"
        style={{ background: c.bg, borderColor: c.border, color: c.text }}>
        {rank}
      </div>
    );
  }
  return (
    <div className="w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold flex-shrink-0"
      style={{ background: 'rgba(255,255,255,0.05)', color: 'rgba(255,255,255,0.4)' }}>
      {rank}
    </div>
  );
};

// ─── Score pill ───────────────────────────────────────────────────────────────
const ScorePill = ({ label, value, accent = COLORS.saffron }) => (
  <div className="flex flex-col items-center gap-0.5 px-3 py-2 rounded-xl"
    style={{ background: `${accent}0E`, border: `1px solid ${accent}20` }}>
    <span className="text-xs font-bold" style={{ color: accent }}>{value}</span>
    <span className="text-xs" style={{ color: 'rgba(255,255,255,0.35)' }}>{label}</span>
  </div>
);

// ─── Skeleton loader ──────────────────────────────────────────────────────────
const SkeletonRow = () => (
  <div className="flex items-center gap-4 p-4 rounded-2xl border animate-pulse"
    style={{ background: 'rgba(255,255,255,0.02)', borderColor: 'rgba(255,255,255,0.05)' }}>
    <div className="w-8 h-8 rounded-full" style={{ background: 'rgba(255,255,255,0.06)' }} />
    <div className="flex-1 space-y-2">
      <div className="h-3 rounded-full w-1/3" style={{ background: 'rgba(255,255,255,0.06)' }} />
      <div className="h-2 rounded-full w-1/4" style={{ background: 'rgba(255,255,255,0.04)' }} />
    </div>
    <div className="h-8 w-16 rounded-xl" style={{ background: 'rgba(255,255,255,0.06)' }} />
  </div>
);

// ─── Player score card ────────────────────────────────────────────────────────
const PlayerScoreCard = ({ player, rank, isTied, index }) => {
  const ref = useRef(null);
  const inView = useInView(ref, { once: true, margin: '-20px' });
  const reduced = useReducedMotion();

  return (
    <motion.div
      ref={ref}
      className="rounded-2xl border overflow-hidden"
      style={{
        background: rank <= 3
          ? `linear-gradient(135deg, ${rank === 1 ? 'rgba(245,166,35,0.08)' : rank === 2 ? 'rgba(192,192,192,0.06)' : 'rgba(205,127,50,0.06)'}, rgba(255,255,255,0.02))`
          : 'rgba(255,255,255,0.02)',
        borderColor: rank === 1 ? 'rgba(245,166,35,0.3)' : rank === 2 ? 'rgba(192,192,192,0.2)' : rank === 3 ? 'rgba(205,127,50,0.2)' : 'rgba(255,255,255,0.06)',
      }}
      initial={reduced ? { opacity: 0 } : { opacity: 0, y: 16 }}
      animate={inView ? { opacity: 1, y: 0 } : {}}
      transition={{ duration: 0.45, delay: index * 0.04, ease: EASE_OUT }}>

      {/* Main row */}
      <div className="flex items-center gap-4 p-4">
        <RankBadge rank={rank} />
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2 flex-wrap">
            <p className="text-white font-bold text-sm leading-tight">{player.playerName}</p>
            {isTied && (
              <span className="text-xs px-2 py-0.5 rounded-full font-bold"
                style={{ background: 'rgba(245,166,35,0.15)', color: '#F5A623', border: '1px solid rgba(245,166,35,0.3)' }}>
                Tied
              </span>
            )}
          </div>
          {player.time && (
            <p className="text-xs mt-0.5" style={{ color: 'rgba(255,255,255,0.35)' }}>Time: {player.time}</p>
          )}
        </div>
        <div className="text-right flex-shrink-0">
          <p className="text-2xl font-black" style={{ color: COLORS.saffron }}>{player.finalScore.toFixed(2)}</p>
          <p className="text-xs" style={{ color: 'rgba(255,255,255,0.3)' }}>Final</p>
        </div>
      </div>

      {/* Score breakdown */}
      <div className="px-4 pb-4 flex flex-wrap gap-2">
        <ScorePill label="Senior" value={player.judgeScores.seniorJudge} accent={COLORS.saffron} />
        <ScorePill label="J1" value={player.judgeScores.judge1} accent="#A855F7" />
        <ScorePill label="J2" value={player.judgeScores.judge2} accent="#3B82F6" />
        <ScorePill label="J3" value={player.judgeScores.judge3} accent="#22C55E" />
        <ScorePill label="J4" value={player.judgeScores.judge4} accent="#F59E0B" />
        <ScorePill label="Avg" value={player.averageMarks.toFixed(2)} accent={COLORS.saffronLight} />
        {player.deduction > 0 && <ScorePill label="Deduct" value={`-${player.deduction}`} accent="#EF4444" />}
        {player.otherDeduction > 0 && <ScorePill label="Other" value={`-${player.otherDeduction}`} accent="#EF4444" />}
        {player.baseScoreApplied && (
          <span className="text-xs px-2 py-1 rounded-xl font-bold self-center"
            style={{ background: 'rgba(168,85,247,0.15)', color: '#C084FC', border: '1px solid rgba(168,85,247,0.25)' }}>
            Base Score
          </span>
        )}
      </div>
    </motion.div>
  );
};

// ─── Score group card ─────────────────────────────────────────────────────────
const ScoreGroupCard = ({ scoreEntry, index }) => {
  const [expanded, setExpanded] = useState(true);

  const sorted = [...scoreEntry.playerScores].sort((a, b) => {
    if (b.finalScore !== a.finalScore) return b.finalScore - a.finalScore;
    if (a.baseScoreApplied && b.baseScoreApplied && a.baseScore !== b.baseScore) return b.baseScore - a.baseScore;
    return b.executionAverage - a.executionAverage;
  });

  return (
    <FadeIn delay={index * 0.08}>
      <div className="rounded-2xl border overflow-hidden"
        style={{ background: 'rgba(255,255,255,0.02)', borderColor: COLORS.darkBorder }}>
        {/* Header */}
        <button
          onClick={() => setExpanded(e => !e)}
          className="w-full flex items-center justify-between px-5 py-4 border-b text-left min-h-[60px]"
          style={{ borderColor: 'rgba(255,255,255,0.05)' }}
          aria-expanded={expanded}>
          <div>
            <p className="text-white font-bold">{scoreEntry.teamName}</p>
            <p className="text-xs mt-0.5" style={{ color: 'rgba(255,255,255,0.4)' }}>
              {scoreEntry.gender} · {scoreEntry.ageGroup} · {new Date(scoreEntry.createdAt).toLocaleDateString()}
            </p>
          </div>
          <div className="flex items-center gap-3">
            <span className="text-xs px-2 py-1 rounded-full font-bold"
              style={{ background: `${COLORS.saffron}15`, color: COLORS.saffronLight, border: `1px solid ${COLORS.saffron}30` }}>
              {sorted.length} players
            </span>
            <motion.div animate={{ rotate: expanded ? 180 : 0 }} transition={{ duration: 0.25 }}>
              <ChevronDown className="w-4 h-4" style={{ color: 'rgba(255,255,255,0.4)' }} aria-hidden="true" />
            </motion.div>
          </div>
        </button>

        <AnimatePresence initial={false}>
          {expanded && (
            <motion.div
              initial={{ height: 0, opacity: 0 }}
              animate={{ height: 'auto', opacity: 1 }}
              exit={{ height: 0, opacity: 0 }}
              transition={{ duration: 0.3, ease: EASE_OUT }}>
              <div className="p-4 space-y-2">
                {sorted.map((player, i, arr) => {
                  const isTied = i > 0 &&
                    arr[i - 1].finalScore === player.finalScore &&
                    arr[i - 1].executionAverage === player.executionAverage;
                  return (
                    <PlayerScoreCard key={player.playerId} player={player} rank={i + 1} isTied={isTied} index={i} />
                  );
                })}
              </div>

              {/* Footer metadata */}
              {(scoreEntry.timeKeeper || scoreEntry.scorer || scoreEntry.remarks) && (
                <div className="px-5 pb-4 pt-2 border-t flex flex-wrap gap-4 text-xs"
                  style={{ borderColor: 'rgba(255,255,255,0.05)' }}>
                  {scoreEntry.timeKeeper && (
                    <span style={{ color: 'rgba(255,255,255,0.35)' }}>
                      <span className="font-bold text-white/60">Timekeeper:</span> {scoreEntry.timeKeeper}
                    </span>
                  )}
                  {scoreEntry.scorer && (
                    <span style={{ color: 'rgba(255,255,255,0.35)' }}>
                      <span className="font-bold text-white/60">Scorer:</span> {scoreEntry.scorer}
                    </span>
                  )}
                  {scoreEntry.remarks && (
                    <span style={{ color: 'rgba(255,255,255,0.35)' }}>
                      <span className="font-bold text-white/60">Remarks:</span> {scoreEntry.remarks}
                    </span>
                  )}
                </div>
              )}
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    </FadeIn>
  );
};

// ─── Dark dropdown wrapper ────────────────────────────────────────────────────
const FilterLabel = ({ children }) => (
  <label className="block text-xs font-bold tracking-widest uppercase mb-2" style={{ color: COLORS.saffron }}>
    {children}
  </label>
);

// ─── Main component ───────────────────────────────────────────────────────────
const PublicScores = () => {
  const [teams, setTeams] = useState([]);
  const [scores, setScores] = useState([]);
  const [loading, setLoading] = useState(false);
  const [selectedTeam, setSelectedTeam] = useState(null);
  const [selectedGender, setSelectedGender] = useState(null);
  const [selectedAgeGroup, setSelectedAgeGroup] = useState(null);
  const [searchTerm, setSearchTerm] = useState('');

  const genders = [
    { value: 'Male', label: 'Male' },
    { value: 'Female', label: 'Female' },
  ];

  const boysAgeGroups = [
    { value: 'Under10', label: 'Under 10' },
    { value: 'Under12', label: 'Under 12' },
    { value: 'Under14', label: 'Under 14' },
    { value: 'Under18', label: 'Under 18' },
    { value: 'Above18', label: 'Above 18' },
  ];

  const girlsAgeGroups = [
    { value: 'Under10', label: 'Under 10' },
    { value: 'Under12', label: 'Under 12' },
    { value: 'Under14', label: 'Under 14' },
    { value: 'Under16', label: 'Under 16' },
    { value: 'Above16', label: 'Above 16' },
  ];

  const getAvailableAgeGroups = () => {
    if (!selectedGender) return [];
    return selectedGender.value === 'Male' ? boysAgeGroups : girlsAgeGroups;
  };

  useEffect(() => { if (selectedGender) setSelectedAgeGroup(null); }, [selectedGender]);
  useEffect(() => { if (selectedTeam) { setSelectedGender(null); setSelectedAgeGroup(null); } }, [selectedTeam]);

  useEffect(() => { fetchTeams(); }, []);

  useEffect(() => {
    if (selectedTeam && selectedGender && selectedAgeGroup) fetchScores();
    else setScores([]);
  }, [selectedTeam, selectedGender, selectedAgeGroup]);

  const fetchTeams = async () => {
    try {
      const response = await publicAPI.getTeams();
      setTeams(response.data.teams || []);
    } catch (error) {
      toast.error('Failed to load teams');
      logger.error('Error fetching teams:', error);
    }
  };

  const fetchScores = async () => {
    if (!selectedTeam || !selectedGender || !selectedAgeGroup) return;
    setLoading(true);
    try {
      const response = await publicAPI.getScores({
        teamId: selectedTeam.value,
        gender: selectedGender.value,
        ageGroup: selectedAgeGroup.value,
      });
      setScores(response.data.scores || []);
      if (!response.data.scores?.length) toast.info('No scores found for this category');
    } catch (error) {
      toast.error('Failed to load scores');
      logger.error('Error fetching scores:', error);
      setScores([]);
    } finally {
      setLoading(false);
    }
  };

  const handleClearFilters = () => {
    setSelectedTeam(null);
    setSelectedGender(null);
    setSelectedAgeGroup(null);
    setScores([]);
    setSearchTerm('');
  };

  const getFilteredScores = () => {
    if (!scores.length) return [];
    return scores.map(entry => ({
      ...entry,
      playerScores: entry.playerScores.filter(p =>
        !searchTerm || p.playerName?.toLowerCase().includes(searchTerm.toLowerCase())
      ),
    })).filter(entry => entry.playerScores.length > 0);
  };

  const allFiltersSet = selectedTeam && selectedGender && selectedAgeGroup;
  const filtered = getFilteredScores();

  return (
    <div className="min-h-dvh relative" style={{ background: COLORS.dark, fontFamily: "'Inter', system-ui, sans-serif" }}>
      {/* Ambient orbs */}
      <Orb x={10} y={15} size={500} color={COLORS.saffron} delay={0} duration={9} blur={120} />
      <Orb x={90} y={50} size={350} color="#A855F7" delay={2} duration={11} blur={100} />
      <Orb x={50} y={90} size={300} color={COLORS.saffronDark} delay={1} duration={8} blur={90} />

      {/* Sticky header */}
      <header className="sticky top-0 z-40 border-b"
        style={{ background: 'rgba(10,10,10,0.92)', backdropFilter: 'blur(20px)', borderColor: COLORS.darkBorder }}>
        <div className="max-w-5xl mx-auto px-4 md:px-8 h-16 flex items-center justify-between gap-4">
          <div className="flex items-center gap-4">
            <Link to="/"
              className="flex items-center gap-2 text-sm font-semibold transition-colors duration-200 min-h-[44px] px-2 rounded-xl hover:bg-white/5"
              style={{ color: 'rgba(255,255,255,0.6)' }}
              aria-label="Back to Home">
              <ArrowLeft className="w-4 h-4" aria-hidden="true" />
              <span className="hidden sm:inline">Home</span>
            </Link>
            <div className="w-px h-5" style={{ background: 'rgba(255,255,255,0.1)' }} />
            <div className="flex items-center gap-2">
              <Trophy className="w-4 h-4 flex-shrink-0" style={{ color: COLORS.saffron }} aria-hidden="true" />
              <h1 className="text-white font-black text-sm sm:text-base">Competition Scores</h1>
            </div>
          </div>
          {allFiltersSet && (
            <button onClick={handleClearFilters}
              className="flex items-center gap-1.5 px-3 py-2 rounded-xl border text-xs font-bold transition-all duration-200 min-h-[36px] hover:bg-white/5"
              style={{ borderColor: 'rgba(255,255,255,0.1)', color: 'rgba(255,255,255,0.5)' }}>
              <X className="w-3.5 h-3.5" aria-hidden="true" />
              Clear
            </button>
          )}
        </div>
      </header>

      <main className="relative z-10 max-w-5xl mx-auto px-4 md:px-8 py-8 space-y-6" id="main-content">
        {/* Page title */}
        <FadeIn>
          <div className="text-center py-4">
            <p className="text-xs font-bold tracking-widest uppercase mb-2" style={{ color: COLORS.saffron }}>Live Results</p>
            <h2 className="text-3xl md:text-4xl font-black text-white">
              View <GradientText>Scores</GradientText>
            </h2>
            <p className="text-sm mt-2" style={{ color: 'rgba(255,255,255,0.4)' }}>
              Select filters to view competition results
            </p>
          </div>
        </FadeIn>

        {/* Filters card */}
        <FadeIn delay={0.1}>
          <div className="rounded-2xl border p-5 md:p-6"
            style={{ background: 'rgba(255,255,255,0.03)', borderColor: COLORS.darkBorder }}>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <div>
                <FilterLabel>Team</FilterLabel>
                <Dropdown
                  options={teams.map(t => ({ value: t._id, label: t.name }))}
                  value={selectedTeam}
                  onChange={setSelectedTeam}
                  placeholder="Choose a team..."
                  className="w-full"
                />
              </div>
              <div>
                <FilterLabel>Gender</FilterLabel>
                <Dropdown
                  options={genders}
                  value={selectedGender}
                  onChange={setSelectedGender}
                  placeholder="Choose gender..."
                  className="w-full"
                  disabled={!selectedTeam}
                />
              </div>
              <div>
                <FilterLabel>Age Group</FilterLabel>
                <Dropdown
                  options={getAvailableAgeGroups()}
                  value={selectedAgeGroup}
                  onChange={setSelectedAgeGroup}
                  placeholder="Choose age group..."
                  className="w-full"
                  disabled={!selectedGender}
                />
              </div>
            </div>
          </div>
        </FadeIn>

        {/* Content area */}
        <AnimatePresence mode="wait">
          {!allFiltersSet ? (
            <motion.div key="empty-state"
              initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0 }}
              transition={{ duration: 0.4 }}
              className="text-center py-20">
              <div className="w-20 h-20 rounded-2xl flex items-center justify-center mx-auto mb-6"
                style={{ background: `${COLORS.saffron}10`, border: `1px solid ${COLORS.saffron}20` }}>
                <Filter className="w-8 h-8" style={{ color: COLORS.saffron }} aria-hidden="true" />
              </div>
              <p className="text-white font-bold text-lg mb-2">Select Filters to View Scores</p>
              <p className="text-sm" style={{ color: 'rgba(255,255,255,0.35)' }}>
                All three filters must be selected to view results
              </p>
            </motion.div>
          ) : loading ? (
            <motion.div key="loading"
              initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
              className="space-y-3">
              {[...Array(4)].map((_, i) => <SkeletonRow key={i} />)}
            </motion.div>
          ) : scores.length > 0 ? (
            <motion.div key="results"
              initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
              className="space-y-4">
              {/* Active filter badge */}
              <div className="flex items-center justify-between flex-wrap gap-3">
                <div className="flex items-center gap-2 px-4 py-2 rounded-full border text-xs font-bold"
                  style={{ background: `${COLORS.saffron}10`, borderColor: `${COLORS.saffron}30`, color: COLORS.saffronLight }}>
                  <Trophy className="w-3.5 h-3.5" aria-hidden="true" />
                  {selectedTeam.label} · {selectedGender.label} · {selectedAgeGroup.label}
                </div>
                {/* Search */}
                <div className="relative">
                  <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 pointer-events-none"
                    style={{ color: 'rgba(255,255,255,0.3)' }} aria-hidden="true" />
                  <input
                    type="text"
                    placeholder="Search players..."
                    value={searchTerm}
                    onChange={e => setSearchTerm(e.target.value)}
                    className="pl-9 pr-8 py-2 rounded-xl border text-sm outline-none transition-all duration-200 min-h-[40px]"
                    style={{
                      background: 'rgba(255,255,255,0.04)',
                      borderColor: searchTerm ? `${COLORS.saffron}50` : 'rgba(255,255,255,0.08)',
                      color: '#fff',
                      width: '200px',
                    }}
                    aria-label="Search players by name"
                  />
                  {searchTerm && (
                    <button onClick={() => setSearchTerm('')}
                      className="absolute right-2 top-1/2 -translate-y-1/2 p-1 rounded-lg hover:bg-white/10 transition-colors"
                      aria-label="Clear search">
                      <X className="w-3.5 h-3.5" style={{ color: 'rgba(255,255,255,0.4)' }} aria-hidden="true" />
                    </button>
                  )}
                </div>
              </div>

              {/* Score groups */}
              {filtered.map((entry, i) => (
                <ScoreGroupCard key={entry._id} scoreEntry={entry} index={i} />
              ))}

              {filtered.length === 0 && searchTerm && (
                <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="text-center py-16">
                  <Search className="w-10 h-10 mx-auto mb-4" style={{ color: 'rgba(255,255,255,0.2)' }} aria-hidden="true" />
                  <p className="text-white font-bold mb-1">No players found</p>
                  <p className="text-sm" style={{ color: 'rgba(255,255,255,0.35)' }}>
                    No results for "{searchTerm}"
                  </p>
                  <button onClick={() => setSearchTerm('')}
                    className="mt-4 text-sm font-bold transition-colors duration-200"
                    style={{ color: COLORS.saffron }}>
                    Clear search
                  </button>
                </motion.div>
              )}
            </motion.div>
          ) : (
            <motion.div key="no-scores"
              initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0 }}
              className="text-center py-20">
              <div className="w-20 h-20 rounded-2xl flex items-center justify-center mx-auto mb-6"
                style={{ background: 'rgba(255,255,255,0.04)', border: '1px solid rgba(255,255,255,0.08)' }}>
                <Medal className="w-8 h-8" style={{ color: 'rgba(255,255,255,0.2)' }} aria-hidden="true" />
              </div>
              <p className="text-white font-bold text-lg mb-2">No Scores Available</p>
              <p className="text-sm" style={{ color: 'rgba(255,255,255,0.35)' }}>
                Scores will appear here after judges complete their scoring.
              </p>
            </motion.div>
          )}
        </AnimatePresence>
      </main>
    </div>
  );
};

export default PublicScores;

import { useState, useRef } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import { ArrowLeft, Mail, Send, Sparkles } from 'lucide-react';
import toast from 'react-hot-toast';
import { useInView } from 'framer-motion';
import { authAPI } from '../../services/api';
import { validateEmailFormat } from '../../utils/validation';
import { logger } from '../../utils/logger';
import BHALogo from '../../assets/BHA.png';
import { COLORS, EASE_OUT } from '../../styles/tokens';
import { useReducedMotion as _useReducedMotion } from '../../hooks/useResponsive';

const useReducedMotion = () => {
  const [reduced] = useState(
    () => typeof window !== 'undefined' && window.matchMedia('(prefers-reduced-motion: reduce)').matches
  );
  return reduced;
};

const AmbientOrb = ({ x, y, size, color, delay, duration, blur = 80 }) => {
  const reduced = useReducedMotion();
  if (reduced) return null;
  return (
    <motion.div
      className="absolute rounded-full pointer-events-none"
      style={{
        left: `${x}%`, top: `${y}%`, width: size, height: size,
        background: `radial-gradient(circle at 35% 35%, ${color}55, ${color}15, transparent 70%)`,
        filter: `blur(${blur}px)`, transform: 'translate(-50%, -50%)',
      }}
      animate={{ y: [0, -30, 0], scale: [1, 1.1, 1], opacity: [0.3, 0.6, 0.3] }}
      transition={{ duration, delay, repeat: Infinity, ease: 'easeInOut' }}
    />
  );
};

const GradientText = ({ children, className = '' }) => (
  <span className={className} style={{
    background: `linear-gradient(135deg, ${COLORS.saffron}, ${COLORS.gold}, ${COLORS.saffronLight})`,
    WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent', backgroundClip: 'text',
  }}>{children}</span>
);

const StyledInput = ({ error, ...props }) => (
  <input
    className="w-full px-4 py-3 rounded-xl text-white text-sm outline-none transition-all duration-200 min-h-[48px] placeholder:text-white/25"
    style={{
      background: 'rgba(255,255,255,0.05)',
      border: `1px solid ${error ? '#EF4444' : COLORS.darkBorderSubtle}`,
      caretColor: COLORS.saffron,
    }}
    onFocus={e => { e.target.style.borderColor = error ? '#EF4444' : COLORS.saffron; e.target.style.boxShadow = `0 0 0 3px ${error ? '#EF444420' : `${COLORS.saffron}20`}`; }}
    onBlur={e => { e.target.style.borderColor = error ? '#EF4444' : COLORS.darkBorderSubtle; e.target.style.boxShadow = 'none'; }}
    {...props}
  />
);


const ForgotPassword = () => {
  const [loading, setLoading] = useState(false);
  const [sent, setSent] = useState(false);
  const [error, setError] = useState('');
  const navigate = useNavigate();
  const reduced = useReducedMotion();
  const cardRef = useRef(null);
  const cardInView = useInView(cardRef, { once: true });

  const { register, handleSubmit, formState: { errors } } = useForm();

  const onSubmit = async (data) => {
    setLoading(true); setSent(false); setError('');
    toast.loading('Sending OTP…', { id: 'forgot-password' });
    try {
      logger.log('🔐 Sending forgot password request for:', data.email);
      const timeout = new Promise((_, r) => setTimeout(() => r(new Error('timeout')), 120000));
      await Promise.race([authAPI.forgotPassword(data.email), timeout]);
      setSent(true);
      toast.success('OTP sent! Check your email.', { id: 'forgot-password' });
      setTimeout(() => navigate('/reset-password', { state: { email: data.email } }), 2000);
    } catch (err) {
      logger.error('❌ Forgot password error:', err);
      let msg = 'An error occurred. Please try again.';
      if (err.message === 'timeout') msg = 'Server is starting up. Please try again in a moment.';
      else if (err.response?.data?.message) msg = err.response.data.message;
      else if (err.message?.includes('Network Error')) msg = 'Network error. Check your connection.';
      setError(msg);
      toast.error(msg, { id: 'forgot-password' });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div
      className="min-h-dvh flex flex-col items-center justify-center px-4 py-12 relative overflow-hidden"
      style={{ background: COLORS.dark, fontFamily: "'Inter', system-ui, sans-serif" }}
    >
      <AmbientOrb x={15} y={20} size={400} color={COLORS.saffron} delay={0} duration={7} blur={120} />
      <AmbientOrb x={85} y={70} size={300} color={COLORS.gold} delay={2} duration={9} blur={100} />

      {!reduced && (
        <div className="absolute bottom-0 left-0 right-0 h-48 pointer-events-none opacity-[0.04]"
          style={{
            backgroundImage: `linear-gradient(${COLORS.saffron}80 1px, transparent 1px), linear-gradient(90deg, ${COLORS.saffron}80 1px, transparent 1px)`,
            backgroundSize: '50px 50px',
            transform: 'perspective(400px) rotateX(60deg)',
            transformOrigin: 'bottom center',
          }}
        />
      )}

      {/* Logo */}
      <motion.div className="mb-8 flex items-center gap-3"
        initial={{ opacity: 0, y: -20 }} animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.6, ease: EASE_OUT }}>
        <Link to="/" aria-label="Back to home">
          <img src={BHALogo} alt="BHA Logo" className="h-12 w-auto object-contain" />
        </Link>
        <div>
          <p className="text-xs font-bold tracking-widest uppercase" style={{ color: COLORS.saffron }}>Bhausaheb Ranade</p>
          <p className="text-white text-sm font-bold leading-tight">Mallakhamb Competition</p>
        </div>
      </motion.div>

      {/* Card */}
      <motion.div ref={cardRef} className="w-full max-w-md relative z-10"
        initial={{ opacity: 0, y: 40, scale: 0.97 }}
        animate={cardInView ? { opacity: 1, y: 0, scale: 1 } : {}}
        transition={{ duration: 0.65, ease: EASE_OUT }}>
        <div className="rounded-3xl p-8 border" style={{
          background: 'rgba(255,255,255,0.03)', backdropFilter: 'blur(24px)',
          borderColor: COLORS.darkBorder,
          boxShadow: `0 40px 80px rgba(0,0,0,0.5), 0 0 0 1px ${COLORS.darkBorderSubtle}`,
        }}>
          {/* Icon + heading */}
          <div className="text-center mb-8">
            <motion.div
              className="inline-flex items-center justify-center w-16 h-16 rounded-2xl mb-5 mx-auto"
              style={{ background: `${COLORS.saffron}18`, border: `1px solid ${COLORS.darkBorder}` }}
              initial={{ scale: 0.7, opacity: 0 }} animate={{ scale: 1, opacity: 1 }}
              transition={{ duration: 0.5, delay: 0.2, type: 'spring', stiffness: 300, damping: 20 }}>
              <Mail className="w-7 h-7" style={{ color: COLORS.saffron }} aria-hidden="true" />
            </motion.div>
            <h1 className="text-2xl font-black text-white mb-2">
              Forgot <GradientText>Password?</GradientText>
            </h1>
            <p className="text-white/45 text-sm leading-relaxed">
              Enter your email and we'll send you a one-time code to reset your password.
            </p>
          </div>

          {/* Form */}
          <form onSubmit={handleSubmit(onSubmit)} noValidate>
            <div className="mb-5">
              <label htmlFor="email" className="block text-sm font-semibold text-white/70 mb-2">
                Email Address <span style={{ color: COLORS.saffron }} aria-hidden="true">*</span>
              </label>
              <StyledInput
                {...register('email', {
                  required: 'Email is required',
                  validate: v => validateEmailFormat(v) || 'Please enter a valid email address',
                })}
                id="email" type="email" autoComplete="email"
                placeholder="you@example.com"
                disabled={loading || sent}
                error={!!errors.email}
                aria-describedby={errors.email ? 'email-error' : undefined}
                aria-invalid={!!errors.email}
              />
              {errors.email && (
                <motion.p id="email-error" role="alert" className="mt-2 text-xs font-medium"
                  style={{ color: '#EF4444' }}
                  initial={{ opacity: 0, y: -4 }} animate={{ opacity: 1, y: 0 }}
                  transition={{ duration: 0.2 }}>
                  {errors.email.message}
                </motion.p>
              )}
            </div>

            <motion.button
              type="submit" disabled={loading || sent}
              className="w-full flex items-center justify-center gap-2 rounded-xl font-bold text-sm text-white min-h-[48px] px-6 transition-all duration-200 cursor-pointer disabled:opacity-60 disabled:cursor-not-allowed"
              style={{ background: `linear-gradient(135deg, ${COLORS.saffron}, ${COLORS.saffronDark})` }}
              whileHover={!loading && !sent ? { scale: 1.02 } : {}}
              whileTap={!loading && !sent ? { scale: 0.97 } : {}}>
              {loading ? (
                <>
                  <motion.div className="w-4 h-4 rounded-full border-2 border-white/30 border-t-white"
                    animate={{ rotate: 360 }} transition={{ duration: 0.8, repeat: Infinity, ease: 'linear' }} />
                  Sending OTP…
                </>
              ) : sent ? (
                <><Sparkles className="w-4 h-4" aria-hidden="true" /> OTP Sent — Redirecting…</>
              ) : (
                <><Send className="w-4 h-4" aria-hidden="true" /> Send OTP</>
              )}
            </motion.button>

            {loading && (
              <motion.div className="mt-4 p-3 rounded-xl border text-xs text-white/50 flex items-center gap-2"
                style={{ background: `${COLORS.saffron}0A`, borderColor: `${COLORS.saffron}20` }}
                initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ duration: 0.25 }}>
                <Mail className="w-3.5 h-3.5 flex-shrink-0" style={{ color: COLORS.saffronLight }} aria-hidden="true" />
                This may take a moment if the server is starting up.
              </motion.div>
            )}
          </form>

          {sent && (
            <motion.div className="mt-5 p-4 rounded-xl border"
              style={{ background: 'rgba(34,197,94,0.08)', borderColor: 'rgba(34,197,94,0.25)' }}
              initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.3 }} role="status" aria-live="polite">
              <p className="text-sm font-semibold text-green-400">OTP sent to your email</p>
              <p className="text-xs text-green-400/70 mt-1">Redirecting to reset page…</p>
            </motion.div>
          )}

          {error && !sent && (
            <motion.div className="mt-5 p-4 rounded-xl border"
              style={{ background: 'rgba(239,68,68,0.08)', borderColor: 'rgba(239,68,68,0.25)' }}
              initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.3 }} role="alert" aria-live="assertive">
              <p className="text-sm text-red-400">{error}</p>
            </motion.div>
          )}

          {/* Footer links */}
          <div className="mt-8 pt-6 border-t flex flex-col items-center gap-3" style={{ borderColor: COLORS.darkBorderSubtle }}>
            <p className="text-sm text-white/35">
              Remember your password?{' '}
              <Link to="/player/login" className="font-semibold transition-colors duration-200 hover:opacity-80"
                style={{ color: COLORS.saffronLight }}>
                Back to Login
              </Link>
            </p>
            <Link to="/" className="inline-flex items-center gap-1.5 text-xs text-white/25 hover:text-white/50 transition-colors duration-200 min-h-[44px]">
              <ArrowLeft className="w-3.5 h-3.5" aria-hidden="true" />
              Back to Home
            </Link>
          </div>
        </div>
      </motion.div>
    </div>
  );
};

export default ForgotPassword;

import { useState, useEffect, useRef } from 'react';
import { Link, useNavigate, useLocation, useParams } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import { ArrowLeft, Lock, Shield, Eye, EyeOff, CheckCircle2, AlertTriangle } from 'lucide-react';
import toast from 'react-hot-toast';
import { useInView, AnimatePresence } from 'framer-motion';
import { authAPI } from '../../services/api';
import BHALogo from '../../assets/BHA.png';

const COLORS = {
  saffron: '#FF6B00',
  saffronLight: '#FF8C38',
  saffronDark: '#CC5500',
  gold: '#F5A623',
  dark: '#0A0A0A',
  darkBorder: 'rgba(255,107,0,0.15)',
  darkBorderSubtle: 'rgba(255,255,255,0.06)',
};

const EASE_OUT = [0.25, 0.46, 0.45, 0.94];

const useReducedMotion = () => {
  const [reduced] = useState(
    () => typeof window !== 'undefined' && window.matchMedia('(prefers-reduced-motion: reduce)').matches
  );
  return reduced;
};

const AmbientOrb = ({ x, y, size, color, delay, duration, blur = 80 }) => {
  const reduced = useReducedMotion();
  if (reduced) return null;
  return (
    <motion.div
      className="absolute rounded-full pointer-events-none"
      style={{
        left: `${x}%`, top: `${y}%`, width: size, height: size,
        background: `radial-gradient(circle at 35% 35%, ${color}55, ${color}15, transparent 70%)`,
        filter: `blur(${blur}px)`, transform: 'translate(-50%, -50%)',
      }}
      animate={{ y: [0, -30, 0], scale: [1, 1.1, 1], opacity: [0.3, 0.6, 0.3] }}
      transition={{ duration, delay, repeat: Infinity, ease: 'easeInOut' }}
    />
  );
};

const GradientText = ({ children, className = '' }) => (
  <span className={className} style={{
    background: `linear-gradient(135deg, ${COLORS.saffron}, ${COLORS.gold}, ${COLORS.saffronLight})`,
    WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent', backgroundClip: 'text',
  }}>{children}</span>
);

const StyledInput = ({ error, verified, ...props }) => (
  <input
    className="w-full px-4 py-3 rounded-xl text-white text-sm outline-none transition-all duration-200 min-h-[48px] placeholder:text-white/25"
    style={{
      background: verified ? 'rgba(34,197,94,0.06)' : 'rgba(255,255,255,0.05)',
      border: `1px solid ${error ? '#EF4444' : verified ? 'rgba(34,197,94,0.4)' : COLORS.darkBorderSubtle}`,
      caretColor: COLORS.saffron,
    }}
    onFocus={e => {
      if (!verified) {
        e.target.style.borderColor = error ? '#EF4444' : COLORS.saffron;
        e.target.style.boxShadow = `0 0 0 3px ${error ? '#EF444420' : `${COLORS.saffron}20`}`;
      }
    }}
    onBlur={e => {
      if (!verified) {
        e.target.style.borderColor = error ? '#EF4444' : COLORS.darkBorderSubtle;
        e.target.style.boxShadow = 'none';
      }
    }}
    {...props}
  />
);

const PasswordInput = ({ error, showPassword, onToggle, ...props }) => (
  <div className="relative">
    <input
      type={showPassword ? 'text' : 'password'}
      className="w-full px-4 py-3 pr-12 rounded-xl text-white text-sm outline-none transition-all duration-200 min-h-[48px] placeholder:text-white/25"
      style={{
        background: 'rgba(255,255,255,0.05)',
        border: `1px solid ${error ? '#EF4444' : COLORS.darkBorderSubtle}`,
        caretColor: COLORS.saffron,
      }}
      onFocus={e => { e.target.style.borderColor = error ? '#EF4444' : COLORS.saffron; e.target.style.boxShadow = `0 0 0 3px ${error ? '#EF444420' : `${COLORS.saffron}20`}`; }}
      onBlur={e => { e.target.style.borderColor = error ? '#EF4444' : COLORS.darkBorderSubtle; e.target.style.boxShadow = 'none'; }}
      {...props}
    />
    <button
      type="button"
      onClick={onToggle}
      className="absolute right-3 top-1/2 -translate-y-1/2 p-1 rounded-lg text-white/35 hover:text-white/70 transition-colors duration-200 min-h-[36px] min-w-[36px] flex items-center justify-center"
      aria-label={showPassword ? 'Hide password' : 'Show password'}
    >
      {showPassword ? <EyeOff className="w-4 h-4" aria-hidden="true" /> : <Eye className="w-4 h-4" aria-hidden="true" />}
    </button>
  </div>
);

const ResetPassword = () => {
  const [loading, setLoading] = useState(false);
  const [verifying, setVerifying] = useState(false);
  const [otpVerified, setOtpVerified] = useState(false);
  const [success, setSuccess] = useState(false);
  const [error, setError] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);
  const [attemptsRemaining, setAttemptsRemaining] = useState(3);
  const [isLockedOut, setIsLockedOut] = useState(false);
  const [lockoutSeconds, setLockoutSeconds] = useState(0);

  const navigate = useNavigate();
  const location = useLocation();
  const { token } = useParams();
  const isOTPMethod = !token;
  const emailFromState = location.state?.email || '';
  const [resetToken, setResetToken] = useState('');
  const reduced = useReducedMotion();
  const cardRef = useRef(null);
  const cardInView = useInView(cardRef, { once: true });

  useEffect(() => {
    if (token) {
      setResetToken(token);
      window.history.replaceState(null, '', '/reset-password');
    }
  }, [token]);

  const { register, handleSubmit, watch, formState: { errors } } = useForm({
    defaultValues: { email: emailFromState },
  });
  const password = watch('password');

  useEffect(() => {
    if (lockoutSeconds <= 0) return;
    const t = setTimeout(() => {
      setLockoutSeconds(p => {
        const n = p - 1;
        if (n <= 0) { setIsLockedOut(false); setAttemptsRemaining(3); }
        return n;
      });
    }, 1000);
    return () => clearTimeout(t);
  }, [lockoutSeconds]);

  const formatTime = s => `${Math.floor(s / 60)}:${(s % 60).toString().padStart(2, '0')}`;

  const handleVerifyOTP = async () => {
    const email = watch('email');
    const otp = watch('otp');
    if (!email || !otp) { toast.error('Please enter email and OTP'); return; }
    if (otp.length !== 6) { toast.error('OTP must be 6 digits'); return; }
    setVerifying(true); setError('');
    try {
      await authAPI.verifyOTP(email, otp);
      setOtpVerified(true);
      setAttemptsRemaining(3);
      toast.success('OTP verified! Set your new password.');
    } catch (err) {
      const msg = err.response?.data?.message || 'Invalid OTP';
      const left = err.response?.data?.attemptsRemaining;
      const locked = err.response?.data?.lockedOut;
      const secs = err.response?.data?.remainingSeconds;
      toast.error(msg); setError(msg);
      if (locked) { setIsLockedOut(true); setLockoutSeconds(secs || 900); setAttemptsRemaining(0); }
      else if (left !== undefined) setAttemptsRemaining(left);
    } finally {
      setVerifying(false);
    }
  };

  const onSubmit = async (data) => {
    if (isLockedOut) { toast.error(`Locked. Try again in ${formatTime(lockoutSeconds)}`); return; }
    setLoading(true); setError('');
    try {
      if (isOTPMethod) {
        await authAPI.resetPasswordWithOTP(data.email, data.otp, data.password);
      } else {
        if (!resetToken) { setError('Invalid reset link. Please request a new one.'); setLoading(false); return; }
        await authAPI.resetPassword(resetToken, data.password);
      }
      setSuccess(true);
      toast.success('Password reset successfully!');
      if (resetToken) setResetToken('');
      setTimeout(() => navigate('/player/login'), 2000);
    } catch (err) {
      const msg = err.response?.data?.message || 'Failed to reset password. Please try again.';
      const left = err.response?.data?.attemptsRemaining;
      const locked = err.response?.data?.lockedOut;
      const secs = err.response?.data?.remainingSeconds;
      setError(msg); toast.error(msg);
      if (isOTPMethod) {
        if (locked) { setIsLockedOut(true); setLockoutSeconds(secs || 900); setAttemptsRemaining(0); }
        else if (left !== undefined) setAttemptsRemaining(left);
      }
    } finally {
      setLoading(false);
    }
  };

  // Step indicator for OTP flow
  const step = !isOTPMethod ? 2 : otpVerified ? 2 : 1;

  return (
    <div
      className="min-h-dvh flex flex-col items-center justify-center px-4 py-12 relative overflow-hidden"
      style={{ background: COLORS.dark, fontFamily: "'Inter', system-ui, sans-serif" }}
    >
      <AmbientOrb x={20} y={15} size={380} color={COLORS.saffron} delay={0} duration={8} blur={120} />
      <AmbientOrb x={80} y={75} size={280} color={COLORS.gold} delay={1.5} duration={10} blur={100} />

      {!reduced && (
        <div className="absolute bottom-0 left-0 right-0 h-48 pointer-events-none opacity-[0.04]"
          style={{
            backgroundImage: `linear-gradient(${COLORS.saffron}80 1px, transparent 1px), linear-gradient(90deg, ${COLORS.saffron}80 1px, transparent 1px)`,
            backgroundSize: '50px 50px',
            transform: 'perspective(400px) rotateX(60deg)',
            transformOrigin: 'bottom center',
          }}
        />
      )}

      {/* Logo */}
      <motion.div className="mb-8 flex items-center gap-3"
        initial={{ opacity: 0, y: -20 }} animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.6, ease: EASE_OUT }}>
        <Link to="/" aria-label="Back to home">
          <img src={BHALogo} alt="BHA Logo" className="h-12 w-auto object-contain" />
        </Link>
        <div>
          <p className="text-xs font-bold tracking-widest uppercase" style={{ color: COLORS.saffron }}>Bhausaheb Ranade</p>
          <p className="text-white text-sm font-bold leading-tight">Mallakhamb Competition</p>
        </div>
      </motion.div>

      {/* Card */}
      <motion.div ref={cardRef} className="w-full max-w-md relative z-10"
        initial={{ opacity: 0, y: 40, scale: 0.97 }}
        animate={cardInView ? { opacity: 1, y: 0, scale: 1 } : {}}
        transition={{ duration: 0.65, ease: EASE_OUT }}>
        <div className="rounded-3xl p-8 border" style={{
          background: 'rgba(255,255,255,0.03)', backdropFilter: 'blur(24px)',
          borderColor: COLORS.darkBorder,
          boxShadow: `0 40px 80px rgba(0,0,0,0.5), 0 0 0 1px ${COLORS.darkBorderSubtle}`,
        }}>
          {/* Icon + heading */}
          <div className="text-center mb-6">
            <motion.div
              className="inline-flex items-center justify-center w-16 h-16 rounded-2xl mb-5 mx-auto"
              style={{ background: `${COLORS.saffron}18`, border: `1px solid ${COLORS.darkBorder}` }}
              initial={{ scale: 0.7, opacity: 0 }} animate={{ scale: 1, opacity: 1 }}
              transition={{ duration: 0.5, delay: 0.2, type: 'spring', stiffness: 300, damping: 20 }}>
              <Lock className="w-7 h-7" style={{ color: COLORS.saffron }} aria-hidden="true" />
            </motion.div>
            <h1 className="text-2xl font-black text-white mb-2">
              Reset <GradientText>Password</GradientText>
            </h1>
            <p className="text-white/45 text-sm">
              {isOTPMethod ? 'Verify your OTP then set a new password' : 'Enter your new password below'}
            </p>
          </div>

          {/* Step indicator (OTP flow only) */}
          {isOTPMethod && (
            <div className="flex items-center gap-2 mb-6">
              {[1, 2].map(s => (
                <div key={s} className="flex items-center gap-2 flex-1">
                  <div className="flex items-center justify-center w-6 h-6 rounded-full text-xs font-bold transition-all duration-300"
                    style={{
                      background: step >= s ? COLORS.saffron : 'rgba(255,255,255,0.08)',
                      color: step >= s ? '#fff' : 'rgba(255,255,255,0.3)',
                    }}>
                    {step > s ? <CheckCircle2 className="w-3.5 h-3.5" aria-hidden="true" /> : s}
                  </div>
                  <span className="text-xs font-medium transition-colors duration-300"
                    style={{ color: step >= s ? 'rgba(255,255,255,0.7)' : 'rgba(255,255,255,0.25)' }}>
                    {s === 1 ? 'Verify OTP' : 'New Password'}
                  </span>
                  {s < 2 && <div className="flex-1 h-px" style={{ background: step > s ? COLORS.saffron : COLORS.darkBorderSubtle }} />}
                </div>
              ))}
            </div>
          )}

          {/* Lockout banner */}
          <AnimatePresence>
            {isLockedOut && (
              <motion.div className="mb-5 p-4 rounded-xl border flex items-start gap-3"
                style={{ background: 'rgba(239,68,68,0.08)', borderColor: 'rgba(239,68,68,0.25)' }}
                initial={{ opacity: 0, y: -8 }} animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -8 }} transition={{ duration: 0.25 }}
                role="alert">
                <Shield className="w-5 h-5 text-red-400 flex-shrink-0 mt-0.5" aria-hidden="true" />
                <div>
                  <p className="text-sm font-semibold text-red-400">Account Temporarily Locked</p>
                  <p className="text-xs text-red-400/70 mt-0.5">Too many failed attempts. Try again in {formatTime(lockoutSeconds)}</p>
                </div>
              </motion.div>
            )}
          </AnimatePresence>

          {/* Attempts warning */}
          <AnimatePresence>
            {isOTPMethod && !isLockedOut && attemptsRemaining < 3 && !otpVerified && (
              <motion.div className="mb-5 p-3 rounded-xl border flex items-center gap-2"
                style={{ background: 'rgba(245,166,35,0.08)', borderColor: 'rgba(245,166,35,0.25)' }}
                initial={{ opacity: 0, y: -8 }} animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0 }} transition={{ duration: 0.25 }}
                role="status" aria-live="polite">
                <AlertTriangle className="w-4 h-4 flex-shrink-0" style={{ color: COLORS.gold }} aria-hidden="true" />
                <p className="text-xs font-medium" style={{ color: COLORS.gold }}>
                  {attemptsRemaining} attempt{attemptsRemaining !== 1 ? 's' : ''} remaining
                </p>
              </motion.div>
            )}
          </AnimatePresence>

          {/* OTP verified banner */}
          <AnimatePresence>
            {otpVerified && (
              <motion.div className="mb-5 p-3 rounded-xl border flex items-center gap-2"
                style={{ background: 'rgba(34,197,94,0.08)', borderColor: 'rgba(34,197,94,0.25)' }}
                initial={{ opacity: 0, scale: 0.97 }} animate={{ opacity: 1, scale: 1 }}
                transition={{ duration: 0.3, type: 'spring', stiffness: 300, damping: 25 }}
                role="status" aria-live="polite">
                <CheckCircle2 className="w-4 h-4 text-green-400 flex-shrink-0" aria-hidden="true" />
                <p className="text-xs font-semibold text-green-400">OTP verified — set your new password below</p>
              </motion.div>
            )}
          </AnimatePresence>

          {/* Form */}
          <form onSubmit={handleSubmit(onSubmit)} noValidate>
            {isOTPMethod && (
              <>
                {/* Email */}
                <div className="mb-4">
                  <label htmlFor="email" className="block text-sm font-semibold text-white/70 mb-2">
                    Email Address <span style={{ color: COLORS.saffron }} aria-hidden="true">*</span>
                  </label>
                  <StyledInput
                    {...register('email', {
                      required: 'Email is required',
                      pattern: { value: /^[^\s@]+@[^\s@]+\.[^\s@]+$/, message: 'Please enter a valid email' },
                    })}
                    id="email" type="email" autoComplete="email"
                    placeholder="you@example.com"
                    disabled={loading || isLockedOut || otpVerified}
                    error={!!errors.email} verified={otpVerified}
                    aria-invalid={!!errors.email}
                  />
                  {errors.email && (
                    <motion.p role="alert" className="mt-1.5 text-xs font-medium" style={{ color: '#EF4444' }}
                      initial={{ opacity: 0, y: -4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.2 }}>
                      {errors.email.message}
                    </motion.p>
                  )}
                </div>

                {/* OTP */}
                <div className="mb-4">
                  <label htmlFor="otp" className="block text-sm font-semibold text-white/70 mb-2">
                    OTP Code <span style={{ color: COLORS.saffron }} aria-hidden="true">*</span>
                  </label>
                  <div className="flex gap-2">
                    <div className="flex-1 relative">
                      <StyledInput
                        {...register('otp', {
                          required: 'OTP is required',
                          pattern: { value: /^\d{6}$/, message: 'OTP must be 6 digits' },
                        })}
                        id="otp" type="text" inputMode="numeric" pattern="[0-9]*" maxLength={6}
                        placeholder="6-digit code"
                        disabled={loading || isLockedOut || otpVerified}
                        error={!!errors.otp} verified={otpVerified}
                        aria-invalid={!!errors.otp}
                      />
                      {otpVerified && (
                        <div className="absolute right-3 top-1/2 -translate-y-1/2">
                          <CheckCircle2 className="w-4 h-4 text-green-400" aria-hidden="true" />
                        </div>
                      )}
                    </div>
                    <motion.button
                      type="button"
                      onClick={handleVerifyOTP}
                      disabled={loading || verifying || isLockedOut || otpVerified}
                      className="px-4 rounded-xl text-sm font-bold min-h-[48px] whitespace-nowrap transition-all duration-200 disabled:opacity-50 disabled:cursor-not-allowed cursor-pointer"
                      style={{
                        background: otpVerified ? 'rgba(34,197,94,0.15)' : `${COLORS.saffron}18`,
                        border: `1px solid ${otpVerified ? 'rgba(34,197,94,0.3)' : COLORS.darkBorder}`,
                        color: otpVerified ? '#4ade80' : COLORS.saffronLight,
                      }}
                      whileHover={!otpVerified && !verifying ? { scale: 1.03 } : {}}
                      whileTap={!otpVerified && !verifying ? { scale: 0.97 } : {}}>
                      {verifying ? (
                        <motion.div className="w-4 h-4 rounded-full border-2 border-current/30 border-t-current mx-auto"
                          animate={{ rotate: 360 }} transition={{ duration: 0.8, repeat: Infinity, ease: 'linear' }} />
                      ) : otpVerified ? '✓ Verified' : 'Verify'}
                    </motion.button>
                  </div>
                  {errors.otp && (
                    <motion.p role="alert" className="mt-1.5 text-xs font-medium" style={{ color: '#EF4444' }}
                      initial={{ opacity: 0, y: -4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.2 }}>
                      {errors.otp.message}
                    </motion.p>
                  )}
                  {!otpVerified && !errors.otp && (
                    <p className="mt-1.5 text-xs text-white/30">Check your email for the 6-digit code</p>
                  )}
                </div>
              </>
            )}

            {/* New password — only shown after OTP verified (or token method) */}
            <AnimatePresence>
              {(!isOTPMethod || otpVerified) && (
                <motion.div
                  initial={{ opacity: 0, y: 12 }} animate={{ opacity: 1, y: 0 }}
                  exit={{ opacity: 0, y: 12 }} transition={{ duration: 0.3 }}>
                  <div className="mb-4">
                    <label htmlFor="password" className="block text-sm font-semibold text-white/70 mb-2">
                      New Password <span style={{ color: COLORS.saffron }} aria-hidden="true">*</span>
                    </label>
                    <PasswordInput
                      {...register('password', {
                        required: 'Password is required',
                        minLength: { value: 8, message: 'Password must be at least 8 characters' },
                      })}
                      id="password" autoComplete="new-password"
                      placeholder="Min. 8 characters"
                      disabled={loading || isLockedOut}
                      error={!!errors.password}
                      showPassword={showPassword}
                      onToggle={() => setShowPassword(p => !p)}
                      aria-invalid={!!errors.password}
                    />
                    {errors.password && (
                      <motion.p role="alert" className="mt-1.5 text-xs font-medium" style={{ color: '#EF4444' }}
                        initial={{ opacity: 0, y: -4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.2 }}>
                        {errors.password.message}
                      </motion.p>
                    )}
                  </div>

                  <div className="mb-6">
                    <label htmlFor="confirmPassword" className="block text-sm font-semibold text-white/70 mb-2">
                      Confirm Password <span style={{ color: COLORS.saffron }} aria-hidden="true">*</span>
                    </label>
                    <PasswordInput
                      {...register('confirmPassword', {
                        required: 'Please confirm your password',
                        validate: v => v === password || 'Passwords do not match',
                      })}
                      id="confirmPassword" autoComplete="new-password"
                      placeholder="Repeat your password"
                      disabled={loading || isLockedOut}
                      error={!!errors.confirmPassword}
                      showPassword={showConfirmPassword}
                      onToggle={() => setShowConfirmPassword(p => !p)}
                      aria-invalid={!!errors.confirmPassword}
                    />
                    {errors.confirmPassword && (
                      <motion.p role="alert" className="mt-1.5 text-xs font-medium" style={{ color: '#EF4444' }}
                        initial={{ opacity: 0, y: -4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.2 }}>
                        {errors.confirmPassword.message}
                      </motion.p>
                    )}
                  </div>
                </motion.div>
              )}
            </AnimatePresence>

            {/* Submit */}
            {(!isOTPMethod || otpVerified) && (
              <motion.button
                type="submit"
                disabled={loading || isLockedOut || success}
                className="w-full flex items-center justify-center gap-2 rounded-xl font-bold text-sm text-white min-h-[48px] px-6 transition-all duration-200 cursor-pointer disabled:opacity-60 disabled:cursor-not-allowed"
                style={{ background: `linear-gradient(135deg, ${COLORS.saffron}, ${COLORS.saffronDark})` }}
                whileHover={!loading && !isLockedOut && !success ? { scale: 1.02 } : {}}
                whileTap={!loading && !isLockedOut && !success ? { scale: 0.97 } : {}}>
                {loading ? (
                  <>
                    <motion.div className="w-4 h-4 rounded-full border-2 border-white/30 border-t-white"
                      animate={{ rotate: 360 }} transition={{ duration: 0.8, repeat: Infinity, ease: 'linear' }} />
                    Resetting Password…
                  </>
                ) : success ? (
                  <><CheckCircle2 className="w-4 h-4" aria-hidden="true" /> Password Reset — Redirecting…</>
                ) : (
                  <><Lock className="w-4 h-4" aria-hidden="true" /> Reset Password</>
                )}
              </motion.button>
            )}
          </form>

          {/* Success */}
          <AnimatePresence>
            {success && (
              <motion.div className="mt-5 p-4 rounded-xl border"
                style={{ background: 'rgba(34,197,94,0.08)', borderColor: 'rgba(34,197,94,0.25)' }}
                initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0 }} transition={{ duration: 0.3 }}
                role="status" aria-live="polite">
                <p className="text-sm font-semibold text-green-400">Password reset successfully!</p>
                <Link to="/player/login" className="text-xs text-green-400/70 hover:text-green-400 transition-colors mt-1 inline-block min-h-[36px] flex items-center">
                  Go to Login →
                </Link>
              </motion.div>
            )}
          </AnimatePresence>

          {/* Error */}
          <AnimatePresence>
            {error && !isLockedOut && !success && (
              <motion.div className="mt-5 p-4 rounded-xl border"
                style={{ background: 'rgba(239,68,68,0.08)', borderColor: 'rgba(239,68,68,0.25)' }}
                initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0 }} transition={{ duration: 0.3 }}
                role="alert" aria-live="assertive">
                <p className="text-sm text-red-400">{error}</p>
              </motion.div>
            )}
          </AnimatePresence>

          {/* Footer links */}
          <div className="mt-8 pt-6 border-t flex flex-col items-center gap-3" style={{ borderColor: COLORS.darkBorderSubtle }}>
            {isOTPMethod ? (
              <p className="text-sm text-white/35">
                Didn't receive OTP?{' '}
                <Link to="/forgot-password" className="font-semibold transition-colors duration-200 hover:opacity-80"
                  style={{ color: COLORS.saffronLight }}>
                  Request New OTP
                </Link>
              </p>
            ) : (
              <p className="text-sm text-white/35">
                Remember your password?{' '}
                <Link to="/player/login" className="font-semibold transition-colors duration-200 hover:opacity-80"
                  style={{ color: COLORS.saffronLight }}>
                  Back to Login
                </Link>
              </p>
            )}
            <Link to="/" className="inline-flex items-center gap-1.5 text-xs text-white/25 hover:text-white/50 transition-colors duration-200 min-h-[44px]">
              <ArrowLeft className="w-3.5 h-3.5" aria-hidden="true" />
              Back to Home
            </Link>
          </div>
        </div>
      </motion.div>
    </div>
  );
};

export default ResetPassword;

