/**
 * UnifiedLogin - Inner component that uses theme context
 */
const UnifiedLoginInner = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const { login, user, userType } = useAuth();
  const theme = useTheme();
  useReducedMotion(); // Initialize for accessibility
  
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [showCompetitionSelection, setShowCompetitionSelection] = useState(false);
  
  const { register, handleSubmit, formState: { errors }, setError } = useForm();
  const { checkRateLimit, recordAttempt, reset } = useRateLimit(5, 60000);
  
  // Detect role from path
  const role = detectRoleFromPath(location.pathname);
  const config = getRoleConfig(role);
  
  // Get API service based on role
  const getAPIService = () => {
    const services = {
      admin: adminAPI,
      superadmin: superAdminAPI,
      coach: coachAPI,
      player: playerAPI,
      judge: null, // Judge uses custom axios call
    };
    return services[role];
  };
  
  // Redirect if already logged in
  useEffect(() => {
    if (user && userType === role && !showCompetitionSelection) {
      const redirectPaths = {
        admin: '/admin/dashboard',
        superadmin: '/superadmin/dashboard',
        coach: '/coach/select-competition',
        player: user.team ? '/player/dashboard' : '/player/select-team',
        judge: '/judge/scoring',
      };
      navigate(redirectPaths[role] || '/');
    }
  }, [user, userType, role, navigate, showCompetitionSelection]);
  
  // Handle form submission
  const onSubmit = async (data) => {
    // Check rate limit
    const { allowed, waitTime } = checkRateLimit();
    if (!allowed) {
      toast.error(`Too many login attempts. Please wait ${waitTime} seconds.`);
      return;
    }
    
    // Validate input based on role
    const schema = role === 'judge' ? judgeLoginSchema : loginSchema;
    const validation = schema.safeParse(data);
    if (!validation.success) {
      validation.error.errors.forEach((err) => {
        setError(err.path[0], { message: err.message });
      });
      return;
    }
    
    setLoading(true);
    try {
      let response;
      
      // Judge login uses different endpoint
      if (role === 'judge') {
        response = await axios.post(
          `${apiConfig.getBaseUrl()}/judge/login`,
          { 
            username: validation.data.username.toLowerCase(), 
            password: validation.data.password 
          },
          { headers: apiConfig.getHeaders() }
        );
        secureStorage.setItem('judge_token', response.data.token);
        secureStorage.setItem('judge_user', JSON.stringify(response.data.judge));
        toast.success(`Welcome ${response.data.judge.name}!`);
        reset();
        navigate('/judge/scoring');
        return;
      }
      
      // Other roles use API service
      const apiService = getAPIService();
      response = await apiService.login(validation.data);
      const { token } = response.data;
      const userData = response.data[role]; // admin, coach, player, etc.
      
      // Store token for player immediately
      if (role === 'player') {
        secureStorage.setItem('player_token', token);
        secureStorage.setItem('player_user', JSON.stringify(userData));
      }
      
      login(userData, token, role);
      toast.success(role === 'coach' ? 'Welcome back, Coach!' : 'Login successful!');
      reset();
      
      // Handle post-login navigation
      if (role === 'admin') {
        setShowCompetitionSelection(true);
      } else if (role === 'coach') {
        try {
          const statusResponse = await coachAPI.getStatus();
          const { step } = statusResponse.data;
          navigate(step === 'create-team' ? '/coach/create-team' : '/coach/select-competition');
        } catch {
          navigate('/coach/select-competition');
        }
      } else if (role === 'player') {
        setTimeout(() => {
          navigate(userData.team ? '/player/dashboard' : '/player/select-team');
        }, 100);
      } else {
        navigate(`/${role}/dashboard`);
      }
    } catch (error) {
      recordAttempt();
      logger.error(`${role} login error:`, error);
      toast.error(error.response?.data?.message || 'Login failed');
    } finally {
      setLoading(false);
    }
  };
  
  // Show competition selection for admin
  if (showCompetitionSelection && role === 'admin') {
    return (
      <CompetitionProvider userType="admin">
        <CompetitionSelectionScreen userType="admin" onCompetitionSelected={() => {}} />
      </CompetitionProvider>
    );
  }
  
  const BackgroundComponent = config.background;
  const OrnamentComponent = config.ornament;
  const IconComponent = config.icon;
  
  return (
    <div className="min-h-dvh flex relative overflow-hidden"
      style={{ 
        background: theme.colors.background, 
        fontFamily: "'Inter', system-ui, sans-serif" 
      }}>
      
      {/* Left decorative panel (desktop) */}
      <div className="hidden lg:flex flex-col items-center justify-center w-[45%] relative border-r"
        style={{ 
          background: theme.colors.card, 
          borderColor: theme.colors.border 
        }}>
        <BackgroundComponent color={theme.colors.primary} />
        
        <div className="relative z-10 text-center px-12">
          <motion.div className="flex items-center justify-center gap-3 mb-12"
            initial={{ opacity: 0, y: -20 }} animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.2, ease: EASE }}>
            <img src={BHALogo} alt="BHA Logo" className="h-12 w-auto object-contain opacity-80" />
          </motion.div>
          
          <div className="mb-10">
            <OrnamentComponent color={theme.colors.primary} />
          </div>
          
          <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.5, ease: EASE }}>
            <p className="text-[11px] font-bold tracking-[0.3em] uppercase mb-3"
              style={{ color: `${theme.colors.primary}80` }}>
              Bhausaheb Ranade Mallakhamb
            </p>
            <h1 className="text-4xl font-black leading-tight mb-3">
              <GradientText colors={[theme.colors.primary, theme.colors.primaryLight, theme.colors.primaryDark]}>
                {config.title}<br />{config.subtitle}
              </GradientText>
            </h1>
            <p className="text-white/30 text-sm leading-relaxed max-w-xs mx-auto">
              {config.description}
            </p>
          </motion.div>
          
          <motion.div className="flex items-center justify-center gap-8 mt-10"
            initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: 0.7 }}>
            {config.features.map(({ icon: FeatureIcon, label }) => (
              <div key={label} className="flex flex-col items-center gap-1.5">
                <div className="w-8 h-8 rounded-lg flex items-center justify-center"
                  style={{ background: `${theme.colors.primary}12`, border: `1px solid ${theme.colors.primary}25` }}>
                  <FeatureIcon className="w-4 h-4" style={{ color: theme.colors.primary }} aria-hidden="true" />
                </div>
                <span className="text-[10px] font-semibold tracking-widest uppercase"
                  style={{ color: `${theme.colors.primary}60` }}>{label}</span>
              </div>
            ))}
          </motion.div>
        </div>
        
        <div className="absolute bottom-0 left-0 right-0 h-px"
          style={{ background: `linear-gradient(90deg, transparent, ${theme.colors.primary}40, transparent)` }} />
      </div>
      
      {/* Right form panel */}
      <div className="flex-1 flex flex-col items-center justify-center relative px-6 py-12">
        <div className="lg:hidden absolute inset-0 pointer-events-none" aria-hidden="true">
          <div className="absolute inset-0"
            style={{ background: `radial-gradient(ellipse at 50% 30%, ${theme.colors.primary}10, transparent 65%)` }} />
        </div>
        
        <motion.div className="lg:hidden flex items-center gap-3 mb-8"
          initial={{ opacity: 0, y: -12 }} animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.15, ease: EASE }}>
          <img src={BHALogo} alt="BHA Logo" className="h-10 w-auto object-contain opacity-75" />
          <div className="w-px h-8 bg-white/10" />
          <div>
            <p className="text-[10px] font-bold tracking-widest uppercase" 
              style={{ color: theme.colors.primary }}>Mallakhamb</p>
            <p className="text-white/30 text-[10px]">{config.title} Portal</p>
          </div>
        </motion.div>
        
        <motion.div className="w-full max-w-sm"
          initial={{ opacity: 0, y: 32 }} animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.7, ease: EASE }}>
          
          <motion.div className="mb-8"
            initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: 0.3 }}>
            <div className="lg:hidden mb-5 flex justify-center">
              <div className="w-16 h-16 rounded-2xl flex items-center justify-center"
                style={{ 
                  background: `${theme.colors.primary}15`, 
                  border: `1px solid ${theme.colors.primary}35` 
                }}>
                <IconComponent className="w-8 h-8" style={{ color: theme.colors.primary }} aria-hidden="true" />
              </div>
            </div>
            
            <div className="flex items-center gap-2 mb-2">
              <div className="h-px flex-1" 
                style={{ background: `linear-gradient(90deg, ${theme.colors.primary}40, transparent)` }} />
              <span className="text-[10px] font-bold tracking-[0.2em] uppercase px-2"
                style={{ color: `${theme.colors.primary}70` }}>{config.accessLabel}</span>
              <div className="h-px flex-1" 
                style={{ background: `linear-gradient(90deg, transparent, ${theme.colors.primary}40)` }} />
            </div>
            <h2 className="text-3xl font-black text-white mt-3">{config.formTitle}</h2>
            <p className="text-white/35 text-sm mt-1">{config.formSubtitle}</p>
          </motion.div>
          
          <form onSubmit={handleSubmit(onSubmit)} noValidate>
            <motion.div className="space-y-4"
              initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: 0.4 }}>
              
              <div>
                <label className="block text-[11px] font-bold tracking-[0.15em] uppercase mb-2"
                  style={{ color: `${theme.colors.primary}90` }} 
                  htmlFor={`${role}-${config.usesEmail ? 'email' : 'username'}`}>
                  {config.usesEmail ? 'Email' : 'Username'} <span style={{ color: '#EF4444' }}>*</span>
                </label>
                <ThemedInput 
                  id={`${role}-${config.usesEmail ? 'email' : 'username'}`}
                  icon={config.usesEmail ? Mail : User}
                  type={config.usesEmail ? 'email' : 'text'}
                  placeholder={config.usesEmail ? `${role}@example.com` : 'Enter your username'}
                  error={errors[config.usesEmail ? 'email' : 'username']}
                  autoComplete={config.usesEmail ? 'email' : 'username'}
                  {...register(config.usesEmail ? 'email' : 'username', {
                    required: `${config.usesEmail ? 'Email' : 'Username'} is required`,
                    ...(config.usesEmail && {
                      pattern: { value: /^\S+@\S+$/i, message: 'Invalid email' }
                    })
                  })}
                />
                <AnimatePresence>
                  {errors[config.usesEmail ? 'email' : 'username'] && (
                    <motion.p className="text-xs mt-1.5" style={{ color: '#EF4444' }}
                      initial={{ opacity: 0, y: -4 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0 }}
                      role="alert">
                      {errors[config.usesEmail ? 'email' : 'username'].message}
                    </motion.p>
                  )}
                </AnimatePresence>
              </div>
              
              <div>
                <label className="block text-[11px] font-bold tracking-[0.15em] uppercase mb-2"
                  style={{ color: `${theme.colors.primary}90` }} htmlFor={`${role}-password`}>
                  Password <span style={{ color: '#EF4444' }}>*</span>
                </label>
                <ThemedInput
                  id={`${role}-password`}
                  icon={Lock}
                  type={showPassword ? 'text' : 'password'}
                  placeholder="••••••••"
                  error={errors.password}
                  autoComplete="current-password"
                  rightElement={
                    <button type="button" onClick={() => setShowPassword(!showPassword)}
                      className="p-1 rounded hover:bg-white/10 transition-colors min-h-[32px] min-w-[32px] flex items-center justify-center"
                      aria-label={showPassword ? 'Hide password' : 'Show password'}>
                      {showPassword
                        ? <EyeOff className="w-4 h-4 text-white/25" />
                        : <Eye className="w-4 h-4 text-white/25" />}
                    </button>
                  }
                  {...register('password', { required: 'Password is required' })}
                />
                <AnimatePresence>
                  {errors.password && (
                    <motion.p className="text-xs mt-1.5" style={{ color: '#EF4444' }}
                      initial={{ opacity: 0, y: -4 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0 }}
                      role="alert">
                      {errors.password.message}
                    </motion.p>
                  )}
                </AnimatePresence>
              </div>
              
              <ThemedButton
                type="submit"
                disabled={loading}
                loading={loading}
                className="w-full mt-2"
              >
                {loading ? 'Signing in...' : config.buttonText}
                {!loading && <ArrowRight className="w-4 h-4 ml-2" aria-hidden="true" />}
              </ThemedButton>
            </motion.div>
          </form>
          
          <motion.div className="mt-7 pt-5 border-t flex items-center justify-between"
            style={{ borderColor: `${theme.colors.primary}12` }}
            initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: 0.65 }}>
            {config.forgotPasswordLink && (
              <Link to={config.forgotPasswordLink}
                className="text-xs transition-colors hover:underline underline-offset-4"
                style={{ color: `${theme.colors.primary}70` }}>
                Forgot password?
              </Link>
            )}
            <div className="flex items-center gap-3 ml-auto">
              <Link to="/" className="text-xs text-white/20 hover:text-white/45 transition-colors">
                ← Home
              </Link>
              {config.registerLink && (
                <>
                  <span className="text-white/15 text-xs">·</span>
                  <Link to={config.registerLink}
                    className="text-xs transition-colors hover:underline underline-offset-4"
                    style={{ color: `${theme.colors.primary}70` }}>
                    Register
                  </Link>
                </>
              )}
            </div>
          </motion.div>
        </motion.div>
      </div>
      
      <motion.div className="absolute right-0 top-0 bottom-0 w-[2px] hidden lg:block"
        style={{ background: `linear-gradient(to bottom, transparent, ${theme.colors.primary}30, transparent)` }}
        initial={{ scaleY: 0 }} animate={{ scaleY: 1 }}
        transition={{ duration: 1.2, delay: 0.4, ease: EASE }} />
    </div>
  );
};

/**
 * UnifiedLogin - Main component with ThemeProvider wrapper
 */
const UnifiedLogin = () => {
  const location = useLocation();
  const role = detectRoleFromPath(location.pathname);
  
  return (
    <ThemeProvider role={role}>
      <UnifiedLoginInner />
    </ThemeProvider>
  );
};

export default UnifiedLogin;

import { useState, useEffect } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import {
  ArrowRight, Eye, EyeOff, Lock, Mail, User, Phone, Building, Calendar,
  UserCheck, UserPlus, Users, Trophy, Layers, Flame, Dumbbell, Star,
} from 'lucide-react';
import toast from 'react-hot-toast';
import { AnimatePresence } from 'framer-motion';
import { useAuth } from '../../App';
import BHALogo from '../../assets/BHA.png';
import { secureStorage } from '../../utils/secureStorage';
import { logger } from '../../utils/logger';

// Design system
import { ThemeProvider, useTheme } from '../../components/design-system/theme';
import { ThemedInput, ThemedButton, ThemedSelect } from '../../components/design-system/forms';
import { HexMesh, RadialBurst } from '../../components/design-system/backgrounds';
import { CoachOrnament, GradientText } from '../../components/design-system/ornaments';
import { useReducedMotion } from '../../components/design-system/animations';

// API services
import { coachAPI, playerAPI } from '../../services/api';

const EASE = [0.22, 1, 0.36, 1];

/**
 * Detect user role from route path.
 * @param {string} pathname - Current route pathname (e.g. "/coach/register")
 * @returns {'coach'|'player'} Detected role
 */
const detectRoleFromPath = (pathname) => {
  const match = pathname.match(/^\/([^/]+)/);
  if (!match) return 'coach';
  const segment = match[1].toLowerCase();
  return segment === 'player' ? 'player' : 'coach';
};

/**
 * Role-specific configuration for UnifiedRegister.
 * @param {'coach'|'player'} role - The user role
 * @returns {Object} Configuration object with title, subtitle, description, and form fields
 */
const getRoleConfig = (role) => {
  const configs = {
    coach: {
      title: 'Coach',
      subtitle: 'Registration',
      description: 'Create your coach account to manage your team and compete.',
      accessLabel: 'Coach Registration',
      formTitle: 'Create Account',
      formSubtitle: 'Register as a coach',
      buttonText: 'Create Account',
      ornament: CoachOrnament,
      background: HexMesh,
      icon: UserCheck,
      features: [
        { icon: Users, label: 'Manage' },
        { icon: Trophy, label: 'Compete' },
        { icon: Layers, label: 'Organize' },
      ],
      loginLink: '/coach/login',
    },
    player: {
      title: 'Athlete',
      subtitle: 'Registration',
      description: 'Register as a player, join your team, and compete in Mallakhamb.',
      accessLabel: 'Player Registration',
      formTitle: 'Create Account',
      formSubtitle: 'Register as a player',
      buttonText: 'Create Account',
      ornament: ({ color }) => (
        <motion.div
          className="relative flex items-center justify-center"
          initial={{ opacity: 0, scale: 0.6 }}
          animate={{ opacity: 1, scale: 1 }}
          transition={{ duration: 0.9, delay: 0.3, type: 'spring', stiffness: 200, damping: 18 }}
        >
          <motion.div
            className="absolute w-24 h-24 rounded-full border"
            style={{ borderColor: `${color}30` }}
            animate={{ scale: [1, 1.06, 1], opacity: [0.6, 1, 0.6] }}
            transition={{ duration: 3, repeat: Infinity, ease: 'easeInOut' }}
          />
          <div
            className="relative w-20 h-20 rounded-2xl flex items-center justify-center"
            style={{
              background: `linear-gradient(135deg, ${color}20, ${color}15)`,
              border: `1px solid ${color}40`,
              boxShadow: `0 0 40px ${color}20, inset 0 1px 0 rgba(255,255,255,0.08)`,
            }}
          >
            <UserPlus className="w-10 h-10" style={{ color }} aria-hidden="true" />
          </div>
        </motion.div>
      ),
      background: RadialBurst,
      icon: UserPlus,
      features: [
        { icon: Flame, label: 'Compete' },
        { icon: Dumbbell, label: 'Train' },
        { icon: Star, label: 'Excel' },
      ],
      loginLink: '/player/login',
    },
  };
  return configs[role] || configs.coach;
};

// ─── Field definitions ────────────────────────────────────────────────────────

const COACH_FIELDS = [
  {
    name: 'name',
    label: 'Full Name',
    type: 'text',
    icon: User,
    placeholder: 'Enter your full name',
    autoComplete: 'name',
    rules: { required: 'Name is required' },
  },
  {
    name: 'email',
    label: 'Email Address',
    type: 'email',
    icon: Mail,
    placeholder: 'coach@example.com',
    autoComplete: 'email',
    rules: {
      required: 'Email is required',
      pattern: { value: /^\S+@\S+$/i, message: 'Invalid email address' },
    },
  },
  {
    name: 'phone',
    label: 'Phone Number',
    type: 'tel',
    icon: Phone,
    placeholder: 'Enter your phone number',
    autoComplete: 'tel',
    rules: { required: 'Phone number is required' },
  },
  {
    name: 'organization',
    label: 'Organization',
    type: 'text',
    icon: Building,
    placeholder: 'Your club or organization (optional)',
    autoComplete: 'organization',
    rules: {},
  },
];

const PLAYER_FIELDS = [
  {
    name: 'firstName',
    label: 'First Name',
    type: 'text',
    icon: User,
    placeholder: 'First name',
    autoComplete: 'given-name',
    rules: { required: 'First name is required' },
    half: true,
  },
  {
    name: 'lastName',
    label: 'Last Name',
    type: 'text',
    icon: User,
    placeholder: 'Last name',
    autoComplete: 'family-name',
    rules: { required: 'Last name is required' },
    half: true,
  },
  {
    name: 'email',
    label: 'Email Address',
    type: 'email',
    icon: Mail,
    placeholder: 'you@example.com',
    autoComplete: 'email',
    rules: {
      required: 'Email is required',
      pattern: { value: /^\S+@\S+$/i, message: 'Invalid email address' },
    },
  },
  {
    name: 'phone',
    label: 'Phone Number',
    type: 'tel',
    icon: Phone,
    placeholder: 'Enter your phone number',
    autoComplete: 'tel',
    rules: { required: 'Phone number is required' },
  },
  {
    name: 'dateOfBirth',
    label: 'Date of Birth',
    type: 'date',
    icon: Calendar,
    autoComplete: 'bday',
    rules: { required: 'Date of birth is required' },
    half: true,
  },
  // gender is rendered separately as a ThemedSelect
];

// ─── Inner component (uses theme context) ─────────────────────────────────────

/**
 * UnifiedRegisterInner - Registration form that adapts to coach or player role.
 */
const UnifiedRegisterInner = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const { login, user, userType } = useAuth();
  const theme = useTheme();
  useReducedMotion(); // Initialize for accessibility

  const [showPassword, setShowPassword] = useState(false);
  const [showConfirm, setShowConfirm] = useState(false);
  const [loading, setLoading] = useState(false);

  const role = detectRoleFromPath(location.pathname);
  const config = getRoleConfig(role);

  const {
    register,
    handleSubmit,
    watch,
    formState: { errors },
  } = useForm();

  const passwordValue = watch('password');

  // Redirect if already authenticated
  useEffect(() => {
    if (user && userType === role) {
      navigate(role === 'coach' ? '/coach/create-team' : '/player/select-team');
    }
  }, [user, userType, role, navigate]);

  const onSubmit = async (data) => {
    setLoading(true);
    try {
      const apiService = role === 'coach' ? coachAPI : playerAPI;
      const response = await apiService.register(data);
      const { token } = response.data;
      const userData = response.data[role]; // coach or player object

      // Store token immediately for player (mirrors existing PlayerRegister behaviour)
      if (role === 'player') {
        secureStorage.setItem('player_token', token);
        secureStorage.setItem('player_user', JSON.stringify(userData));
      }

      login(userData, token, role);
      toast.success('Registration successful!');

      const destination = role === 'coach' ? '/coach/create-team' : '/player/select-team';
      // Small delay ensures storage is committed before navigation
      setTimeout(() => navigate(destination), 100);
    } catch (error) {
      logger.error(`${role} registration error:`, error);
      toast.error(error.response?.data?.message || 'Registration failed');
    } finally {
      setLoading(false);
    }
  };

  const BackgroundComponent = config.background;
  const OrnamentComponent = config.ornament;
  const IconComponent = config.icon;
  const fields = role === 'coach' ? COACH_FIELDS : PLAYER_FIELDS;

  // Group half-width player fields into pairs
  const renderFields = () => {
    const result = [];
    let i = 0;
    while (i < fields.length) {
      const field = fields[i];
      const next = fields[i + 1];
      if (field.half && next?.half) {
        result.push(
          <div key={`pair-${i}`} className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            {renderField(field)}
            {renderField(next)}
          </div>
        );
        i += 2;
      } else {
        result.push(<div key={field.name}>{renderField(field)}</div>);
        i += 1;
      }
    }
    return result;
  };

  const renderField = (field) => (
    <div key={field.name}>
      <label
        htmlFor={`${role}-reg-${field.name}`}
        className="block text-[11px] font-bold tracking-[0.15em] uppercase mb-2"
        style={{ color: `${theme.colors.primary}90` }}
      >
        {field.label}
        {field.rules?.required && (
          <span style={{ color: '#EF4444' }} aria-hidden="true"> *</span>
        )}
      </label>
      <ThemedInput
        id={`${role}-reg-${field.name}`}
        icon={field.icon}
        type={field.type}
        placeholder={field.placeholder}
        autoComplete={field.autoComplete}
        error={errors[field.name]?.message}
        aria-required={!!field.rules?.required}
        aria-describedby={errors[field.name] ? `${role}-reg-${field.name}-error` : undefined}
        {...register(field.name, field.rules)}
      />
      <AnimatePresence>
        {errors[field.name] && (
          <motion.p
            id={`${role}-reg-${field.name}-error`}
            className="text-xs mt-1.5"
            style={{ color: '#EF4444' }}
            initial={{ opacity: 0, y: -4 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0 }}
            role="alert"
            aria-live="polite"
          >
            {errors[field.name].message}
          </motion.p>
        )}
      </AnimatePresence>
    </div>
  );

  return (
    <div
      className="min-h-dvh flex relative overflow-hidden"
      style={{ background: theme.colors.background, fontFamily: "'Inter', system-ui, sans-serif" }}
    >
      {/* ── Left decorative panel (desktop only) ── */}
      <div
        className="hidden lg:flex flex-col items-center justify-center w-[45%] relative border-r"
        style={{ background: theme.colors.card, borderColor: theme.colors.border }}
      >
        <BackgroundComponent color={theme.colors.primary} />

        <div className="relative z-10 text-center px-12">
          <motion.div
            className="flex items-center justify-center gap-3 mb-12"
            initial={{ opacity: 0, y: -20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.2, ease: EASE }}
          >
            <img src={BHALogo} alt="BHA Logo" className="h-12 w-auto object-contain opacity-80" />
          </motion.div>

          <div className="mb-10">
            <OrnamentComponent color={theme.colors.primary} />
          </div>

          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.5, ease: EASE }}
          >
            <p
              className="text-[11px] font-bold tracking-[0.3em] uppercase mb-3"
              style={{ color: `${theme.colors.primary}80` }}
            >
              Bhausaheb Ranade Mallakhamb
            </p>
            <h1 className="text-4xl font-black leading-tight mb-3">
              <GradientText
                colors={[theme.colors.primary, theme.colors.primaryLight, theme.colors.primaryDark]}
              >
                {config.title}
                <br />
                {config.subtitle}
              </GradientText>
            </h1>
            <p className="text-white/30 text-sm leading-relaxed max-w-xs mx-auto">
              {config.description}
            </p>
          </motion.div>

          <motion.div
            className="flex items-center justify-center gap-8 mt-10"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.7 }}
          >
            {config.features.map(({ icon: FeatureIcon, label }) => (
              <div key={label} className="flex flex-col items-center gap-1.5">
                <div
                  className="w-8 h-8 rounded-lg flex items-center justify-center"
                  style={{
                    background: `${theme.colors.primary}12`,
                    border: `1px solid ${theme.colors.primary}25`,
                  }}
                >
                  <FeatureIcon
                    className="w-4 h-4"
                    style={{ color: theme.colors.primary }}
                    aria-hidden="true"
                  />
                </div>
                <span
                  className="text-[10px] font-semibold tracking-widest uppercase"
                  style={{ color: `${theme.colors.primary}60` }}
                >
                  {label}
                </span>
              </div>
            ))}
          </motion.div>
        </div>

        <div
          className="absolute bottom-0 left-0 right-0 h-px"
          style={{
            background: `linear-gradient(90deg, transparent, ${theme.colors.primary}40, transparent)`,
          }}
        />
      </div>

      {/* ── Right form panel ── */}
      <div className="flex-1 flex flex-col items-center justify-center relative px-6 py-12 overflow-y-auto">
        {/* Mobile background glow */}
        <div className="lg:hidden absolute inset-0 pointer-events-none" aria-hidden="true">
          <div
            className="absolute inset-0"
            style={{
              background: `radial-gradient(ellipse at 50% 30%, ${theme.colors.primary}10, transparent 65%)`,
            }}
          />
        </div>

        {/* Mobile logo */}
        <motion.div
          className="lg:hidden flex items-center gap-3 mb-8"
          initial={{ opacity: 0, y: -12 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.15, ease: EASE }}
        >
          <img src={BHALogo} alt="BHA Logo" className="h-10 w-auto object-contain opacity-75" />
          <div className="w-px h-8 bg-white/10" />
          <div>
            <p
              className="text-[10px] font-bold tracking-widest uppercase"
              style={{ color: theme.colors.primary }}
            >
              Mallakhamb
            </p>
            <p className="text-white/30 text-[10px]">{config.title} Portal</p>
          </div>
        </motion.div>

        <motion.div
          className="w-full max-w-sm"
          initial={{ opacity: 0, y: 32 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.7, ease: EASE }}
        >
          {/* Form header */}
          <motion.div
            className="mb-8"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.3 }}
          >
            <div className="lg:hidden mb-5 flex justify-center">
              <div
                className="w-16 h-16 rounded-2xl flex items-center justify-center"
                style={{
                  background: `${theme.colors.primary}15`,
                  border: `1px solid ${theme.colors.primary}35`,
                }}
              >
                <IconComponent
                  className="w-8 h-8"
                  style={{ color: theme.colors.primary }}
                  aria-hidden="true"
                />
              </div>
            </div>

            <div className="flex items-center gap-2 mb-2">
              <div
                className="h-px flex-1"
                style={{
                  background: `linear-gradient(90deg, ${theme.colors.primary}40, transparent)`,
                }}
              />
              <span
                className="text-[10px] font-bold tracking-[0.2em] uppercase px-2"
                style={{ color: `${theme.colors.primary}70` }}
              >
                {config.accessLabel}
              </span>
              <div
                className="h-px flex-1"
                style={{
                  background: `linear-gradient(90deg, transparent, ${theme.colors.primary}40)`,
                }}
              />
            </div>
            <h2 className="text-3xl font-black text-white mt-3">{config.formTitle}</h2>
            <p className="text-white/35 text-sm mt-1">{config.formSubtitle}</p>
          </motion.div>

          {/* Registration form */}
          <form onSubmit={handleSubmit(onSubmit)} noValidate aria-label={`${config.title} registration form`}>
            <motion.div
              className="space-y-4"
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={{ delay: 0.4 }}
            >
              {/* Role-specific fields */}
              {renderFields()}

              {/* Gender select (player only) */}
              {role === 'player' && (
                <div>
                  <label
                    htmlFor="player-reg-gender"
                    className="block text-[11px] font-bold tracking-[0.15em] uppercase mb-2"
                    style={{ color: `${theme.colors.primary}90` }}
                  >
                    Gender <span style={{ color: '#EF4444' }} aria-hidden="true">*</span>
                  </label>
                  <ThemedSelect
                    id="player-reg-gender"
                    placeholder="Select gender"
                    options={[
                      { value: 'Male', label: 'Male' },
                      { value: 'Female', label: 'Female' },
                    ]}
                    aria-required="true"
                    aria-describedby={errors.gender ? 'player-reg-gender-error' : undefined}
                    {...register('gender', { required: 'Gender is required' })}
                  />
                  <AnimatePresence>
                    {errors.gender && (
                      <motion.p
                        id="player-reg-gender-error"
                        className="text-xs mt-1.5"
                        style={{ color: '#EF4444' }}
                        initial={{ opacity: 0, y: -4 }}
                        animate={{ opacity: 1, y: 0 }}
                        exit={{ opacity: 0 }}
                        role="alert"
                        aria-live="polite"
                      >
                        {errors.gender.message}
                      </motion.p>
                    )}
                  </AnimatePresence>
                </div>
              )}

              {/* Password */}
              <div>
                <label
                  htmlFor={`${role}-reg-password`}
                  className="block text-[11px] font-bold tracking-[0.15em] uppercase mb-2"
                  style={{ color: `${theme.colors.primary}90` }}
                >
                  Password <span style={{ color: '#EF4444' }} aria-hidden="true">*</span>
                </label>
                <ThemedInput
                  id={`${role}-reg-password`}
                  icon={Lock}
                  type={showPassword ? 'text' : 'password'}
                  placeholder="Min. 6 characters"
                  autoComplete="new-password"
                  error={errors.password?.message}
                  aria-required="true"
                  aria-describedby={errors.password ? `${role}-reg-password-error` : undefined}
                  rightElement={
                    <button
                      type="button"
                      onClick={() => setShowPassword((v) => !v)}
                      className="p-1 rounded hover:bg-white/10 transition-colors min-h-[32px] min-w-[32px] flex items-center justify-center"
                      aria-label={showPassword ? 'Hide password' : 'Show password'}
                    >
                      {showPassword
                        ? <EyeOff className="w-4 h-4 text-white/25" />
                        : <Eye className="w-4 h-4 text-white/25" />}
                    </button>
                  }
                  {...register('password', {
                    required: 'Password is required',
                    minLength: { value: 6, message: 'Password must be at least 6 characters' },
                  })}
                />
                <AnimatePresence>
                  {errors.password && (
                    <motion.p
                      id={`${role}-reg-password-error`}
                      className="text-xs mt-1.5"
                      style={{ color: '#EF4444' }}
                      initial={{ opacity: 0, y: -4 }}
                      animate={{ opacity: 1, y: 0 }}
                      exit={{ opacity: 0 }}
                      role="alert"
                      aria-live="polite"
                    >
                      {errors.password.message}
                    </motion.p>
                  )}
                </AnimatePresence>
              </div>

              {/* Confirm Password */}
              <div>
                <label
                  htmlFor={`${role}-reg-confirmPassword`}
                  className="block text-[11px] font-bold tracking-[0.15em] uppercase mb-2"
                  style={{ color: `${theme.colors.primary}90` }}
                >
                  Confirm Password <span style={{ color: '#EF4444' }} aria-hidden="true">*</span>
                </label>
                <ThemedInput
                  id={`${role}-reg-confirmPassword`}
                  icon={Lock}
                  type={showConfirm ? 'text' : 'password'}
                  placeholder="Re-enter your password"
                  autoComplete="new-password"
                  error={errors.confirmPassword?.message}
                  aria-required="true"
                  aria-describedby={errors.confirmPassword ? `${role}-reg-confirmPassword-error` : undefined}
                  rightElement={
                    <button
                      type="button"
                      onClick={() => setShowConfirm((v) => !v)}
                      className="p-1 rounded hover:bg-white/10 transition-colors min-h-[32px] min-w-[32px] flex items-center justify-center"
                      aria-label={showConfirm ? 'Hide confirm password' : 'Show confirm password'}
                    >
                      {showConfirm
                        ? <EyeOff className="w-4 h-4 text-white/25" />
                        : <Eye className="w-4 h-4 text-white/25" />}
                    </button>
                  }
                  {...register('confirmPassword', {
                    required: 'Please confirm your password',
                    validate: (value) =>
                      value === passwordValue || 'Passwords do not match',
                  })}
                />
                <AnimatePresence>
                  {errors.confirmPassword && (
                    <motion.p
                      id={`${role}-reg-confirmPassword-error`}
                      className="text-xs mt-1.5"
                      style={{ color: '#EF4444' }}
                      initial={{ opacity: 0, y: -4 }}
                      animate={{ opacity: 1, y: 0 }}
                      exit={{ opacity: 0 }}
                      role="alert"
                      aria-live="polite"
                    >
                      {errors.confirmPassword.message}
                    </motion.p>
                  )}
                </AnimatePresence>
              </div>

              {/* Submit */}
              <ThemedButton
                type="submit"
                disabled={loading}
                loading={loading}
                className="w-full mt-2"
              >
                {loading ? 'Creating Account...' : config.buttonText}
                {!loading && <ArrowRight className="w-4 h-4 ml-2" aria-hidden="true" />}
              </ThemedButton>
            </motion.div>
          </form>

          {/* Footer links */}
          <motion.div
            className="mt-7 pt-5 border-t flex items-center justify-between"
            style={{ borderColor: `${theme.colors.primary}12` }}
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.65 }}
          >
            <Link
              to="/"
              className="text-xs text-white/20 hover:text-white/45 transition-colors"
            >
              ← Home
            </Link>
            <div className="flex items-center gap-3">
              <span className="text-white/15 text-xs">·</span>
              <Link
                to={config.loginLink}
                className="text-xs transition-colors hover:underline underline-offset-4"
                style={{ color: `${theme.colors.primary}70` }}
              >
                Sign in
              </Link>
            </div>
          </motion.div>
        </motion.div>
      </div>

      {/* Right edge accent line */}
      <motion.div
        className="absolute right-0 top-0 bottom-0 w-[2px] hidden lg:block"
        style={{
          background: `linear-gradient(to bottom, transparent, ${theme.colors.primary}30, transparent)`,
        }}
        initial={{ scaleY: 0 }}
        animate={{ scaleY: 1 }}
        transition={{ duration: 1.2, delay: 0.4, ease: EASE }}
      />
    </div>
  );
};

// ─── Main export with ThemeProvider wrapper ───────────────────────────────────

/**
 * UnifiedRegister - Role-adaptive registration page for Coach and Player.
 *
 * Detects role from route path:
 * - /coach/register → Coach registration (green theme)
 * - /player/register → Player registration (saffron theme)
 *
 * Validates Requirements: 4.1–4.8, 7.1, 8.2, 8.4, 8.7, 12.2–12.5, 17.2, 17.3, 17.8
 */
const UnifiedRegister = () => {
  const location = useLocation();
  const role = detectRoleFromPath(location.pathname);

  return (
    <ThemeProvider role={role}>
      <UnifiedRegisterInner />
    </ThemeProvider>
  );
};

export default UnifiedRegister;

import { describe, it, expect, vi, beforeEach } from 'vitest';
import { render, screen, waitFor } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { MemoryRouter } from 'react-router-dom';
import React from 'react';
import UnifiedRegister from './UnifiedRegister';
import { ThemeProvider } from '../../components/design-system/theme/ThemeProvider';
import * as api from '../../services/api';

// ─── Mocks ────────────────────────────────────────────────────────────────────

vi.mock('../../services/api');
vi.mock('../../utils/logger');
vi.mock('../../utils/secureStorage', () => ({
  secureStorage: { setItem: vi.fn(), getItem: vi.fn(), removeItem: vi.fn() },
}));

vi.mock('react-hot-toast', () => ({
  default: { success: vi.fn(), error: vi.fn() },
}));

// Mock lazy-loaded ornaments so Suspense resolves immediately
vi.mock('../../components/design-system/ornaments', () => ({
  CoachOrnament: ({ color }) => <div data-testid="coach-ornament" style={{ color }} />,
  ShieldOrnament: ({ color }) => <div data-testid="shield-ornament" style={{ color }} />,
  GradientText: ({ children }) => <span data-testid="gradient-text">{children}</span>,
}));

// Mock framer-motion to render plain HTML elements (avoids animation issues in tests)
vi.mock('framer-motion', () => ({
  motion: {
    div: ({ children, whileFocus, whileHover, whileTap, initial, animate, exit, transition, ...props }) => <div {...props}>{children}</div>,
    input: React.forwardRef(({ whileFocus, whileHover, whileTap, initial, animate, exit, transition, ...props }, ref) => (
      <input ref={ref} {...props} />
    )),
    button: ({ children, whileFocus, whileHover, whileTap, initial, animate, exit, transition, ...props }) => (
      <button {...props}>{children}</button>
    ),
    p: ({ children, whileFocus, whileHover, whileTap, initial, animate, exit, transition, ...props }) => (
      <p {...props}>{children}</p>
    ),
    select: React.forwardRef(({ children, whileFocus, whileHover, whileTap, initial, animate, exit, transition, ...props }, ref) => (
      <select ref={ref} {...props}>{children}</select>
    )),
  },
  AnimatePresence: ({ children }) => <>{children}</>,
  useReducedMotion: () => false,
}));

const mockNavigate = vi.fn();
vi.mock('react-router-dom', async (importOriginal) => {
  const actual = await importOriginal();
  return { ...actual, useNavigate: () => mockNavigate };
});

vi.mock('../../App', () => ({
  useAuth: () => ({ login: vi.fn(), user: null, userType: null }),
}));

vi.mock('../../hooks/useResponsive', () => ({
  useResponsive: () => ({
    isMobile: false,
    isTablet: false,
    isDesktop: true,
    getResponsiveValue: (v) => (typeof v === 'string' ? v : v.desktop ?? 'md'),
  }),
}));

// ─── Helpers ──────────────────────────────────────────────────────────────────

const renderAt = (route) =>
  render(
    <MemoryRouter initialEntries={[route]}>
      <ThemeProvider>
        <React.Suspense fallback={<div>Loading...</div>}>
          <UnifiedRegister />
        </React.Suspense>
      </ThemeProvider>
    </MemoryRouter>
  );

// Use querySelector to avoid label-text ambiguity for password fields
const getPasswordInput = (container, role) =>
  container.querySelector(`#${role}-reg-password`);

const getConfirmPasswordInput = (container, role) =>
  container.querySelector(`#${role}-reg-confirmPassword`);

// ─── Tests ────────────────────────────────────────────────────────────────────

describe('UnifiedRegister', () => {
  beforeEach(() => {
    vi.clearAllMocks();
    mockNavigate.mockReset();
  });

  // ── Role detection ──────────────────────────────────────────────────────────

  describe('Role detection', () => {
    it('renders coach registration at /coach/register', async () => {
      renderAt('/coach/register');
      await waitFor(() => expect(screen.getByText(/coach registration/i)).toBeInTheDocument(), { timeout: 3000 });
    });

    it('renders player registration at /player/register', async () => {
      renderAt('/player/register');
      await waitFor(() => expect(screen.getByText(/player registration/i)).toBeInTheDocument(), { timeout: 3000 });
    });

    it('defaults to coach for unknown paths', async () => {
      renderAt('/unknown/register');
      await waitFor(() => expect(screen.getByText(/coach registration/i)).toBeInTheDocument());
    });
  });

  // ── Coach form fields ───────────────────────────────────────────────────────

  describe('Coach form fields', () => {
    it('shows name, email, phone, organization, password, confirm password', async () => {
      const { container } = renderAt('/coach/register');
      await waitFor(() => expect(screen.getByLabelText(/full name/i)).toBeInTheDocument());
      expect(screen.getByLabelText(/email address/i)).toBeInTheDocument();
      expect(screen.getByLabelText(/phone number/i)).toBeInTheDocument();
      expect(screen.getByLabelText(/organization/i)).toBeInTheDocument();
      expect(getPasswordInput(container, 'coach')).toBeInTheDocument();
      expect(getConfirmPasswordInput(container, 'coach')).toBeInTheDocument();
    });

    it('does NOT show date of birth or gender for coach', async () => {
      renderAt('/coach/register');
      await waitFor(() => expect(screen.getByLabelText(/full name/i)).toBeInTheDocument());
      expect(screen.queryByLabelText(/date of birth/i)).not.toBeInTheDocument();
      expect(screen.queryByLabelText(/gender/i)).not.toBeInTheDocument();
    });
  });

  // ── Player form fields ──────────────────────────────────────────────────────

  describe('Player form fields', () => {
    it('shows first name, last name, email, phone, dob, gender, password, confirm password', async () => {
      const { container } = renderAt('/player/register');
      await waitFor(() => expect(screen.getByLabelText(/first name/i)).toBeInTheDocument());
      expect(screen.getByLabelText(/last name/i)).toBeInTheDocument();
      expect(screen.getByLabelText(/email address/i)).toBeInTheDocument();
      expect(screen.getByLabelText(/phone number/i)).toBeInTheDocument();
      expect(screen.getByLabelText(/date of birth/i)).toBeInTheDocument();
      expect(screen.getByLabelText(/gender/i)).toBeInTheDocument();
      expect(getPasswordInput(container, 'player')).toBeInTheDocument();
      expect(getConfirmPasswordInput(container, 'player')).toBeInTheDocument();
    });

    it('does NOT show organization for player', async () => {
      renderAt('/player/register');
      await waitFor(() => expect(screen.getByLabelText(/first name/i)).toBeInTheDocument());
      expect(screen.queryByLabelText(/organization/i)).not.toBeInTheDocument();
    });
  });

  // ── Form validation ─────────────────────────────────────────────────────────

  describe('Form validation', () => {
    it('shows required errors when submitting empty coach form', async () => {
      const user = userEvent.setup();
      renderAt('/coach/register');
      await waitFor(() => expect(screen.getByRole('button', { name: /create account/i })).toBeInTheDocument());
      await user.click(screen.getByRole('button', { name: /create account/i }));
      await waitFor(() => {
        const alerts = screen.getAllByRole('alert');
        expect(alerts.some(a => a.textContent.includes('Name is required'))).toBe(true);
        expect(alerts.some(a => a.textContent.includes('Email is required'))).toBe(true);
        expect(alerts.some(a => a.textContent.includes('Phone number is required'))).toBe(true);
        expect(alerts.some(a => a.textContent.includes('Password is required'))).toBe(true);
      });
    });

    it('shows invalid email error', async () => {
      const user = userEvent.setup();
      renderAt('/coach/register');
      await waitFor(() => expect(screen.getByLabelText(/email address/i)).toBeInTheDocument());
      await user.type(screen.getByLabelText(/email address/i), 'not-an-email');
      await user.click(screen.getByRole('button', { name: /create account/i }));
      await waitFor(() => {
        const alerts = screen.getAllByRole('alert');
        expect(alerts.some(a => a.textContent.includes('Invalid email'))).toBe(true);
      });
    });

    it('shows password too short error', async () => {
      const user = userEvent.setup();
      const { container } = renderAt('/coach/register');
      await waitFor(() => expect(getPasswordInput(container, 'coach')).toBeInTheDocument());
      await user.type(getPasswordInput(container, 'coach'), '123');
      await user.click(screen.getByRole('button', { name: /create account/i }));
      await waitFor(() => {
        const alerts = screen.getAllByRole('alert');
        expect(alerts.some(a => a.textContent.includes('at least 6 characters'))).toBe(true);
      });
    });

    it('shows passwords do not match error', async () => {
      const user = userEvent.setup();
      const { container } = renderAt('/coach/register');
      await waitFor(() => expect(getPasswordInput(container, 'coach')).toBeInTheDocument());
      await user.type(getPasswordInput(container, 'coach'), 'password123');
      await user.type(getConfirmPasswordInput(container, 'coach'), 'different123');
      await user.click(screen.getByRole('button', { name: /create account/i }));
      await waitFor(() => {
        const alerts = screen.getAllByRole('alert');
        const passwordMismatchAlert = alerts.find(alert => alert.textContent.includes('Passwords do not match'));
        expect(passwordMismatchAlert).toBeInTheDocument();
      });
    });

    it('shows required errors when submitting empty player form', async () => {
      const user = userEvent.setup();
      renderAt('/player/register');
      await waitFor(() => expect(screen.getByRole('button', { name: /create account/i })).toBeInTheDocument());
      await user.click(screen.getByRole('button', { name: /create account/i }));
      await waitFor(() => {
        const alerts = screen.getAllByRole('alert');
        // Check for at least the main required fields
        expect(alerts.some(a => a.textContent.includes('First name is required'))).toBe(true);
        expect(alerts.some(a => a.textContent.includes('Last name is required'))).toBe(true);
        expect(alerts.some(a => a.textContent.includes('Email is required'))).toBe(true);
        expect(alerts.some(a => a.textContent.includes('Date of birth is required'))).toBe(true);
      });
    });
  });

  // ── API integration ─────────────────────────────────────────────────────────

  describe('API integration', () => {
    it('calls coachAPI.register with form data on coach registration', async () => {
      const user = userEvent.setup();
      api.coachAPI = {
        register: vi.fn().mockResolvedValue({
          data: { token: 'coach-token', coach: { _id: '1', name: 'Test Coach' } },
        }),
      };

      const { container } = renderAt('/coach/register');
      await waitFor(() => expect(screen.getByLabelText(/full name/i)).toBeInTheDocument());

      await user.type(screen.getByLabelText(/full name/i), 'Test Coach');
      await user.type(screen.getByLabelText(/email address/i), 'coach@test.com');
      await user.type(screen.getByLabelText(/phone number/i), '1234567890');
      await user.type(getPasswordInput(container, 'coach'), 'password123');
      await user.type(getConfirmPasswordInput(container, 'coach'), 'password123');
      await user.click(screen.getByRole('button', { name: /create account/i }));

      await waitFor(() => {
        expect(api.coachAPI.register).toHaveBeenCalledWith(
          expect.objectContaining({ name: 'Test Coach', email: 'coach@test.com' })
        );
      });
    });

    it('calls playerAPI.register with form data on player registration', async () => {
      const user = userEvent.setup();
      api.playerAPI = {
        register: vi.fn().mockResolvedValue({
          data: { token: 'player-token', player: { _id: '2', firstName: 'Test' } },
        }),
      };

      const { container } = renderAt('/player/register');
      await waitFor(() => expect(screen.getByLabelText(/first name/i)).toBeInTheDocument());

      await user.type(screen.getByLabelText(/first name/i), 'Test');
      await user.type(screen.getByLabelText(/last name/i), 'Player');
      await user.type(screen.getByLabelText(/email address/i), 'player@test.com');
      await user.type(screen.getByLabelText(/phone number/i), '9876543210');
      await user.type(screen.getByLabelText(/date of birth/i), '2000-01-01');
      await user.selectOptions(screen.getByLabelText(/gender/i), 'Male');
      await user.type(getPasswordInput(container, 'player'), 'password123');
      await user.type(getConfirmPasswordInput(container, 'player'), 'password123');
      await user.click(screen.getByRole('button', { name: /create account/i }));

      await waitFor(() => {
        expect(api.playerAPI.register).toHaveBeenCalledWith(
          expect.objectContaining({ firstName: 'Test', email: 'player@test.com' })
        );
      });
    });
  });

  // ── Navigation after registration ───────────────────────────────────────────

  describe('Post-registration navigation', () => {
    it('navigates coach to /coach/create-team after successful registration', async () => {
      const user = userEvent.setup();
      api.coachAPI = {
        register: vi.fn().mockResolvedValue({
          data: { token: 'tok', coach: { _id: '1', name: 'Coach' } },
        }),
      };

      const { container } = renderAt('/coach/register');
      await waitFor(() => expect(screen.getByLabelText(/full name/i)).toBeInTheDocument());

      await user.type(screen.getByLabelText(/full name/i), 'Coach');
      await user.type(screen.getByLabelText(/email address/i), 'c@test.com');
      await user.type(screen.getByLabelText(/phone number/i), '1234567890');
      await user.type(getPasswordInput(container, 'coach'), 'pass123');
      await user.type(getConfirmPasswordInput(container, 'coach'), 'pass123');
      await user.click(screen.getByRole('button', { name: /create account/i }));

      await waitFor(() => expect(api.coachAPI.register).toHaveBeenCalled());
      await waitFor(() => expect(mockNavigate).toHaveBeenCalledWith('/coach/create-team'), { timeout: 2000 });
    });

    it('navigates player to /player/select-team after successful registration', async () => {
      const user = userEvent.setup();
      api.playerAPI = {
        register: vi.fn().mockResolvedValue({
          data: { token: 'tok', player: { _id: '2', firstName: 'Player' } },
        }),
      };

      const { container } = renderAt('/player/register');
      await waitFor(() => expect(screen.getByLabelText(/first name/i)).toBeInTheDocument());

      await user.type(screen.getByLabelText(/first name/i), 'Player');
      await user.type(screen.getByLabelText(/last name/i), 'One');
      await user.type(screen.getByLabelText(/email address/i), 'p@test.com');
      await user.type(screen.getByLabelText(/phone number/i), '9876543210');
      await user.type(screen.getByLabelText(/date of birth/i), '2000-01-01');
      await user.selectOptions(screen.getByLabelText(/gender/i), 'Female');
      await user.type(getPasswordInput(container, 'player'), 'pass123');
      await user.type(getConfirmPasswordInput(container, 'player'), 'pass123');
      await user.click(screen.getByRole('button', { name: /create account/i }));

      await waitFor(() => expect(api.playerAPI.register).toHaveBeenCalled());
      await waitFor(() => expect(mockNavigate).toHaveBeenCalledWith('/player/select-team'), { timeout: 2000 });
    });
  });

  // ── Error handling ──────────────────────────────────────────────────────────

  describe('Error handling', () => {
    it('shows API error message on failed coach registration', async () => {
      const toast = (await import('react-hot-toast')).default;
      const user = userEvent.setup();
      api.coachAPI = {
        register: vi.fn().mockRejectedValue({
          response: { data: { message: 'Email already in use' } },
        }),
      };

      const { container } = renderAt('/coach/register');
      await waitFor(() => expect(screen.getByLabelText(/full name/i)).toBeInTheDocument());

      await user.type(screen.getByLabelText(/full name/i), 'Coach');
      await user.type(screen.getByLabelText(/email address/i), 'taken@test.com');
      await user.type(screen.getByLabelText(/phone number/i), '1234567890');
      await user.type(getPasswordInput(container, 'coach'), 'pass123');
      await user.type(getConfirmPasswordInput(container, 'coach'), 'pass123');
      await user.click(screen.getByRole('button', { name: /create account/i }));

      await waitFor(() => {
        expect(toast.error).toHaveBeenCalledWith('Email already in use');
      });
    });

    it('shows fallback error message when no API message provided', async () => {
      const toast = (await import('react-hot-toast')).default;
      const user = userEvent.setup();
      api.coachAPI = {
        register: vi.fn().mockRejectedValue(new Error('Network error')),
      };

      const { container } = renderAt('/coach/register');
      await waitFor(() => expect(screen.getByLabelText(/full name/i)).toBeInTheDocument());

      await user.type(screen.getByLabelText(/full name/i), 'Coach');
      await user.type(screen.getByLabelText(/email address/i), 'c@test.com');
      await user.type(screen.getByLabelText(/phone number/i), '1234567890');
      await user.type(getPasswordInput(container, 'coach'), 'pass123');
      await user.type(getConfirmPasswordInput(container, 'coach'), 'pass123');
      await user.click(screen.getByRole('button', { name: /create account/i }));

      await waitFor(() => {
        expect(toast.error).toHaveBeenCalledWith('Registration failed');
      });
    });
  });

  // ── Accessibility ───────────────────────────────────────────────────────────

  describe('Accessibility', () => {
    it('all form inputs have associated labels', async () => {
      renderAt('/coach/register');
      await waitFor(() => expect(screen.getByLabelText(/full name/i)).toBeInTheDocument());
      const inputs = screen.getAllByRole('textbox');
      inputs.forEach((input) => {
        expect(input).toHaveAttribute('id');
      });
    });

    it('password toggle buttons have aria-labels', async () => {
      renderAt('/coach/register');
      await waitFor(() => expect(screen.getByLabelText(/full name/i)).toBeInTheDocument());
      // At least one password toggle should be present (password field)
      const toggles = screen.getAllByRole('button', { name: /show password|hide password/i });
      expect(toggles.length).toBeGreaterThanOrEqual(1);
    });

    it('error messages have role="alert"', async () => {
      const user = userEvent.setup();
      renderAt('/coach/register');
      await waitFor(() => expect(screen.getByRole('button', { name: /create account/i })).toBeInTheDocument());
      await user.click(screen.getByRole('button', { name: /create account/i }));
      await waitFor(() => {
        const alerts = screen.getAllByRole('alert');
        expect(alerts.length).toBeGreaterThan(0);
      });
    });

    it('form has accessible name', async () => {
      renderAt('/coach/register');
      await waitFor(() =>
        expect(screen.getByRole('form', { name: /coach registration form/i })).toBeInTheDocument()
      );
    });
  });

  // ── Password visibility toggle ──────────────────────────────────────────────

  describe('Password visibility toggle', () => {
    it('toggles password field visibility', async () => {
      const user = userEvent.setup();
      const { container } = renderAt('/coach/register');
      await waitFor(() => expect(getPasswordInput(container, 'coach')).toBeInTheDocument());
      const passwordInput = getPasswordInput(container, 'coach');
      expect(passwordInput).toHaveAttribute('type', 'password');

      const toggleBtn = screen.getAllByRole('button', { name: /show password/i })[0];
      await user.click(toggleBtn);
      expect(passwordInput).toHaveAttribute('type', 'text');

      await user.click(screen.getAllByRole('button', { name: /hide password/i })[0]);
      expect(passwordInput).toHaveAttribute('type', 'password');
    });
  });
});
